import 'package:flutter/material.dart';

void main() {
  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  // This widget is the root of your application.
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Flutter Demo',
      theme: ThemeData(
        // This is the theme of your application.
        //
        // TRY THIS: Try running your application with "flutter run". You'll see
        // the application has a purple toolbar. Then, without quitting the app,
        // try changing the seedColor in the colorScheme below to Colors.green
        // and then invoke "hot reload" (save your changes or press the "hot
        // reload" button in a Flutter-supported IDE, or press "r" if you used
        // the command line to start the app).
        //
        // Notice that the counter didn't reset back to zero; the application
        // state is not lost during the reload. To reset the state, use hot
        // restart instead.
        //
        // This works for code too, not just values: Most code changes can be
        // tested with just a hot reload.
        colorScheme: .fromSeed(seedColor: Colors.deepPurple),
      ),
      home: const MyHomePage(title: 'Flutter Demo Home Page'),
    );
  }
}

class MyHomePage extends StatefulWidget {
  const MyHomePage({super.key, required this.title});

  // This widget is the home page of your application. It is stateful, meaning
  // that it has a State object (defined below) that contains fields that affect
  // how it looks.

  // This class is the configuration for the state. It holds the values (in this
  // case the title) provided by the parent (in this case the App widget) and
  // used by the build method of the State. Fields in a Widget subclass are
  // always marked "final".

  final String title;

  @override
  State<MyHomePage> createState() => _MyHomePageState();
}

class _MyHomePageState extends State<MyHomePage> {
  int _counter = 0;

  void _incrementCounter() {
    setState(() {
      // This call to setState tells the Flutter framework that something has
      // changed in this State, which causes it to rerun the build method below
      // so that the display can reflect the updated values. If we changed
      // _counter without calling setState(), then the build method would not be
      // called again, and so nothing would appear to happen.
      _counter++;
    });
  }

  @override
  Widget build(BuildContext context) {
    // This method is rerun every time setState is called, for instance as done
    // by the _incrementCounter method above.
    //
    // The Flutter framework has been optimized to make rerunning build methods
    // fast, so that you can just rebuild anything that needs updating rather
    // than having to individually change instances of widgets.
    return Scaffold(
      appBar: AppBar(
        // TRY THIS: Try changing the color here to a specific color (to
        // Colors.amber, perhaps?) and trigger a hot reload to see the AppBar
        // change color while the other colors stay the same.
        backgroundColor: Theme.of(context).colorScheme.inversePrimary,
        // Here we take the value from the MyHomePage object that was created by
        // the App.build method, and use it to set our appbar title.
        title: Text(widget.title),
      ),
      body: Center(
        // Center is a layout widget. It takes a single child and positions it
        // in the middle of the parent.
        child: Column(
          // Column is also a layout widget. It takes a list of children and
          // arranges them vertically. By default, it sizes itself to fit its
          // children horizontally, and tries to be as tall as its parent.
          //
          // Column has various properties to control how it sizes itself and
          // how it positions its children. Here we use mainAxisAlignment to
          // center the children vertically; the main axis here is the vertical
          // axis because Columns are vertical (the cross axis would be
          // horizontal).
          //
          // TRY THIS: Invoke "debug painting" (choose the "Toggle Debug Paint"
          // action in the IDE, or press "p" in the console), to see the
          // wireframe for each widget.
          mainAxisAlignment: .center,
          children: [
            const Text('You have pushed the button this many times:'),
            Text(
              '$_counter',
              style: Theme.of(context).textTheme.headlineMedium,
            ),
          ],
        ),
      ),
      floatingActionButton: FloatingActionButton(
        onPressed: _incrementCounter,
        tooltip: 'Increment',
        child: const Icon(Icons.add),
      ),
    );
  }
}

import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';

import 'network/isolate/isolate_messages.dart';
import 'ui/providers/network_state_provider.dart';
import 'ui/screens/chat_screen.dart';
import 'ui/screens/home_screen.dart';
import 'ui/screens/network_status_screen.dart';

void main() {
  WidgetsFlutterBinding.ensureInitialized();
  runApp(const ProviderScope(child: StageSyncApp()));
}

// ─────────────────────────────────────────────────────────────────────────────

class StageSyncApp extends StatelessWidget {
  const StageSyncApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'StageSync',
      debugShowCheckedModeBanner: false,
      theme: ThemeData(
        colorScheme: ColorScheme.fromSeed(
          seedColor: const Color(0xFF6B3FA0), // theater violet
          brightness: Brightness.dark,
        ),
        useMaterial3: true,
      ),
      home: const _NetworkBootstrap(),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Bootstrap: wartet auf Isolate-Init
// ─────────────────────────────────────────────────────────────────────────────

class _NetworkBootstrap extends ConsumerWidget {
  const _NetworkBootstrap();

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final managerAsync = ref.watch(networkIsolateManagerProvider);
    return managerAsync.when(
      loading: () => const _SplashScreen(),
      error: (e, st) => _ErrorScreen(error: e.toString()),
      data: (_) => const _AppShell(),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Splash
// ─────────────────────────────────────────────────────────────────────────────

class _SplashScreen extends StatelessWidget {
  const _SplashScreen();

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: SafeArea(
        child: Center(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              Icon(Icons.theater_comedy,
                  size: 72,
                  color: Theme.of(context)
                      .colorScheme
                      .primary
                      .withOpacity(0.8)),
              const SizedBox(height: 24),
              Text('StageSync',
                  style: Theme.of(context).textTheme.headlineLarge?.copyWith(
                        fontWeight: FontWeight.bold,
                      )),
              const SizedBox(height: 8),
              const Text('Netzwerk wird initialisiert…',
                  style: TextStyle(color: Colors.white54)),
              const SizedBox(height: 32),
              const SizedBox(
                  width: 200, child: LinearProgressIndicator()),
            ],
          ),
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Error
// ─────────────────────────────────────────────────────────────────────────────

class _ErrorScreen extends StatelessWidget {
  final String error;
  const _ErrorScreen({required this.error});

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Center(
        child: Padding(
          padding: const EdgeInsets.all(24),
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              const Icon(Icons.error_outline, size: 52, color: Colors.red),
              const SizedBox(height: 16),
              const Text('Netzwerk-Stack failed',
                  style: TextStyle(
                      fontSize: 18, fontWeight: FontWeight.bold)),
              const SizedBox(height: 8),
              Text(error,
                  textAlign: TextAlign.center,
                  style: const TextStyle(color: Colors.white54)),
            ],
          ),
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// App Shell – Multi-Screen mit NavigationBar
// ─────────────────────────────────────────────────────────────────────────────

class _AppShell extends ConsumerStatefulWidget {
  const _AppShell();

  @override
  ConsumerState<_AppShell> createState() => _AppShellState();
}

class _AppShellState extends ConsumerState<_AppShell> {
  int _selectedIndex = 0;

  static const _screens = [
    HomeScreen(),
    NetworkStatusScreen(),
    ChatScreen(),
    // Weitere Tools werden hier als zusätzliche Einträge hinzugefügt.
  ];

  @override
  Widget build(BuildContext context) {
    final status = ref.watch(networkStatusProvider);
    final isLeader = ref.watch(isLeaderProvider);

    return Scaffold(
      body: IndexedStack(
        index: _selectedIndex,
        children: _screens,
      ),
      bottomNavigationBar: NavigationBar(
        selectedIndex: _selectedIndex,
        onDestinationSelected: (i) => setState(() => _selectedIndex = i),
        destinations: [
          // Home
          const NavigationDestination(
            icon: Icon(Icons.home_outlined),
            selectedIcon: Icon(Icons.home),
            label: 'Home',
          ),

          // Netzwerk
          NavigationDestination(
            icon: Badge(
              isLabelVisible: (status?.connectedPeerCount ?? 0) > 0,
              label: Text('${status?.connectedPeerCount ?? 0}'),
              child: Icon(
                isLeader ? Icons.hub : Icons.hub_outlined,
              ),
            ),
            selectedIcon: Icon(isLeader ? Icons.hub : Icons.hub_outlined),
            label: 'Netzwerk',
          ),

          // Chat
          NavigationDestination(
            icon: _ChatNavIcon(status: status),
            selectedIcon: const Icon(Icons.chat_bubble),
            label: 'Chat',
          ),
        ],
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Chat NavIcon mit Verbindungs-Dot
// ─────────────────────────────────────────────────────────────────────────────

class _ChatNavIcon extends StatelessWidget {
  final NetworkStatusEvent? status;
  const _ChatNavIcon({required this.status});

  @override
  Widget build(BuildContext context) {
    final connected = (status?.connectedPeerCount ?? 0) > 0 ||
        (status?.hasServerConnection ?? false);
    return Stack(
      clipBehavior: Clip.none,
      children: [
        const Icon(Icons.chat_bubble_outline),
        if (connected)
          Positioned(
            top: -2,
            right: -2,
            child: Container(
              width: 8,
              height: 8,
              decoration: const BoxDecoration(
                color: Colors.green,
                shape: BoxShape.circle,
              ),
            ),
          ),
      ],
    );
  }
}

/// ble_mesh_service.dart
/// ──────────────────────
/// Handles all Bluetooth Low Energy operations using flutter_reactive_ble.
///
/// ## Architecture
///
/// StageSync uses a **dual-role BLE topology**:
///   * **Central role** (scanner + GATT client)  – discovers peers, connects
///     to them, and writes data packets to their GATT characteristic.
///   * **Peripheral role** (advertiser + GATT server) – makes THIS device
///     discoverable; receives data written to its own characteristic.
///
/// NOTE: flutter_reactive_ble supports the Central role natively on both
/// Android and iOS. The Peripheral / GATT-Server role on iOS requires the
/// device to be in the foreground (CBPeripheralManager limitation).
/// On Android, peripheral mode works in the background.
///
/// ## GATT Profile
///   Service UUID:        [kStageSyncServiceUuid]
///   Characteristic UUID: [kStageSyncCharUuid]
///     Properties: WRITE (client → server), NOTIFY (server → client)
///
/// ## Data Flow
///   Send:    caller → [sendPacket] → GATT Write → peer's [onRawPacket] stream
///   Receive: peer writes to our GATT char → [onRawPacket] stream → AES-GCM
///            decrypt → parseBlePacket → caller
library ble_mesh_service;

import 'dart:async';
import 'dart:typed_data';

import 'package:flutter_reactive_ble/flutter_reactive_ble.dart';

import '../crypto/aes_gcm_service.dart';
import '../models/ble_packet.dart';
import '../platform/abstract_ble_service.dart';
import '../routing/peer_registry.dart';

// Re-exportieren damit bestehende Imports nicht brechen
export '../platform/abstract_ble_service.dart' show IncomingBlePacket;

/// StageSync BLE Service UUID – change to your own registered UUID.
const String kStageSyncServiceUuid = '4A4D4553-482D-0000-0000-535441474553';

/// Characteristic used for bidirectional data exchange.
const String kStageSyncCharUuid = '4A4D4553-482D-0001-0000-535441474553';

/// How often to scan for new peers (ms between scan windows).
const int kScanRestartIntervalMs = 5000;

// ─────────────────────────────────────────────────────────────────────────────

/// Ein empfangenes, bereits entschlüsseltes BLE-Paket von einem Peer.
// IncomingBlePacket ist jetzt in abstract_ble_service.dart definiert (re-exportiert oben).

// ─────────────────────────────────────────────────────────────────────────────

class BleMeshService implements AbstractBleService {
  final PeerRegistry _peers;
  final AesGcmService _crypto;

  final FlutterReactiveBle _ble = FlutterReactiveBle();

  // Stream controller for all decoded incoming packets.
  final StreamController<IncomingBlePacket> _incomingController =
      StreamController.broadcast();

  // Active BLE scan subscription.
  StreamSubscription<DiscoveredDevice>? _scanSub;

  // Map of deviceId → active connection subscription.
  final Map<String, StreamSubscription<ConnectionStateUpdate>> _connections = {};

  // Map of deviceId → characteristic subscription (for NOTIFY).
  final Map<String, StreamSubscription<List<int>>> _notifySubscriptions = {};

  // Timer for periodic scan restarts.
  Timer? _scanRestartTimer;

  BleMeshService({
    required PeerRegistry peers,
    required AesGcmService crypto,
  })  : _peers = peers,
        _crypto = crypto;

  // ─── Public Streams ───────────────────────────────────────────────────────

  /// All decoded, decrypted packets received from any peer.
  Stream<IncomingBlePacket> get onPacketReceived => _incomingController.stream;

  // ─── Lifecycle ────────────────────────────────────────────────────────────

  /// Start scanning and make this device connectable.
  Future<void> start() async {
    _startScan();
    _scheduleScanRestart();
  }

  /// Stop all BLE operations cleanly.
  Future<void> stop() async {
    _scanRestartTimer?.cancel();
    await _scanSub?.cancel();
    await Future.wait(_connections.values.map((s) => s.cancel()));
    await Future.wait(_notifySubscriptions.values.map((s) => s.cancel()));
    _connections.clear();
    _notifySubscriptions.clear();
    await _incomingController.close();
  }

  // ─── Send ─────────────────────────────────────────────────────────────────

  /// Encrypts [packet] bytes and writes them to [targetDeviceId]'s GATT
  /// characteristic. Connects to the device if not already connected.
  ///
  /// Throws on connection failure or GATT write error.
  Future<void> sendPacket(String targetDeviceId, Uint8List plainPacketBytes) async {
    // Encrypt before sending.
    final encrypted = await _crypto.encrypt(plainPacketBytes);

    // Ensure we have a connection.
    if (!_connections.containsKey(targetDeviceId)) {
      await _connectToDevice(targetDeviceId);
    }

    final characteristic = QualifiedCharacteristic(
      serviceId: Uuid.parse(kStageSyncServiceUuid),
      characteristicId: Uuid.parse(kStageSyncCharUuid),
      deviceId: targetDeviceId,
    );

    await _ble.writeCharacteristicWithResponse(
      characteristic,
      value: encrypted,
    );
  }

  // ─── Private – Scanning ──────────────────────────────────────────────────

  void _startScan() {
    _scanSub?.cancel();
    _scanSub = _ble
        .scanForDevices(
          withServices: [Uuid.parse(kStageSyncServiceUuid)],
          scanMode: ScanMode.lowLatency,
        )
        .listen(_onDeviceDiscovered, onError: _onScanError);
  }

  void _scheduleScanRestart() {
    _scanRestartTimer?.cancel();
    _scanRestartTimer = Timer.periodic(
      Duration(milliseconds: kScanRestartIntervalMs),
      (_) {
        _startScan();
        // Evict stale peers and fire peer-change callbacks.
        _peers.evictStale();
      },
    );
  }

  void _onDeviceDiscovered(DiscoveredDevice device) {
    final shortId = shortIdFromString(device.id);
    _peers.touchPeer(
      deviceId: device.id,
      deviceShortId: shortId,
      rssi: device.rssi,
    );
    // Auto-connect if not already connected to exchange queued packets.
    if (!_connections.containsKey(device.id)) {
      _connectToDevice(device.id).ignore();
    }
  }

  void _onScanError(Object error) {
    // Log and continue – scan errors are transient (e.g. BT toggled).
    // In production, surface via an error event to the coordinator.
  }

  // ─── Private – Connection ────────────────────────────────────────────────

  Future<void> _connectToDevice(String deviceId) async {
    final completer = Completer<void>();

    final sub = _ble
        .connectToDevice(
          id: deviceId,
          connectionTimeout: const Duration(seconds: 10),
        )
        .listen(
          (state) {
            if (state.connectionState == DeviceConnectionState.connected) {
              if (!completer.isCompleted) completer.complete();
              _subscribeToNotifications(deviceId);
            } else if (state.connectionState ==
                    DeviceConnectionState.disconnected &&
                _connections.containsKey(deviceId)) {
              _onDeviceDisconnected(deviceId);
            }
          },
          onError: (e) {
            if (!completer.isCompleted) completer.completeError(e);
          },
        );

    _connections[deviceId] = sub;

    // Wait up to 10 seconds for connection.
    await completer.future.timeout(const Duration(seconds: 10), onTimeout: () {
      sub.cancel();
      _connections.remove(deviceId);
    });
  }

  void _subscribeToNotifications(String deviceId) {
    _notifySubscriptions[deviceId]?.cancel();

    final characteristic = QualifiedCharacteristic(
      serviceId: Uuid.parse(kStageSyncServiceUuid),
      characteristicId: Uuid.parse(kStageSyncCharUuid),
      deviceId: deviceId,
    );

    _notifySubscriptions[deviceId] = _ble
        .subscribeToCharacteristic(characteristic)
        .listen(
          (rawBytes) => _onRawBytesReceived(deviceId, Uint8List.fromList(rawBytes)),
          onError: (_) => _onDeviceDisconnected(deviceId),
        );
  }

  void _onDeviceDisconnected(String deviceId) {
    _connections[deviceId]?.cancel();
    _connections.remove(deviceId);
    _notifySubscriptions[deviceId]?.cancel();
    _notifySubscriptions.remove(deviceId);
  }

  // ─── Private – Receive ───────────────────────────────────────────────────

  Future<void> _onRawBytesReceived(String senderDeviceId, Uint8List encrypted) async {
    try {
      final plainBytes = await _crypto.decrypt(encrypted);
      final packet = parseBlePacket(plainBytes);
      _incomingController.add(
        IncomingBlePacket(senderDeviceId: senderDeviceId, packet: packet),
      );
    } on FormatException {
      // Malformed packet – discard silently.
    } catch (_) {
      // Authentication failure (tampered packet) or other error – discard.
    }
  }
}

/// gossip_engine.dart
/// ────────────────────
/// Implements the **Gossip Protocol** for multi-hop packet propagation in the
/// BLE Mesh. Instead of flooding the entire network (which wastes bandwidth and
/// battery), each node forwards a packet to a random subset of **3** neighbours.
///
/// ## Loop Prevention
/// Every received packet is hashed and stored in a fixed-size LRU "seen" cache
/// with a 60-second TTL. If the same packet arrives again (via a different relay
/// path), it is silently discarded before forwarding.
///
/// ## TTL Enforcement
/// Each packet carries a TTL byte. The engine decrements TTL before relaying;
/// if TTL reaches 0 the packet is dropped and is NOT forwarded further.
///
/// ## Store-Carry-Forward Integration
/// If fewer than [kGossipFanout] peers are in range, the packet is still
/// forwarded to however many are available. If 0 peers are available, the
/// [PacketQueueDao] is called to persist the packet for later delivery.
library gossip_engine;

import 'dart:async';
import 'dart:collection';
import 'dart:typed_data';

import '../crypto/aes_gcm_service.dart';
import '../db/dao/packet_queue_dao.dart';
import '../models/ble_packet.dart';
import '../platform/abstract_ble_service.dart';
import '../routing/peer_registry.dart';
import '../routing/peer_registry.dart' show PeerInfo;
import 'ble_mesh_service.dart' show BleMeshService; // für Rückwärtskompatibilität

/// Number of random peers to forward each packet to.
const int kGossipFanout = 3;

/// Maximum number of packet hashes in the seen-cache.
const int kSeenCacheMaxSize = 2000;

/// Milliseconds before a seen-cache entry expires.
const int kSeenCacheTtlMs = 60 * 1000;

// ─────────────────────────────────────────────────────────────────────────────

/// Entry in the seen-packet cache.
class _SeenEntry {
  final int insertedAtMs;
  _SeenEntry(this.insertedAtMs);
  bool get isExpired =>
      DateTime.now().millisecondsSinceEpoch - insertedAtMs > kSeenCacheTtlMs;
}

// ─────────────────────────────────────────────────────────────────────────────

class GossipEngine {
  final AbstractBleService _ble;
  final PeerRegistry _peers;
  final AesGcmService _crypto;
  final PacketQueueDao _queue;
  final int _localShortId;

  /// Seen-packet cache: dedupKey → _SeenEntry.
  /// Using LinkedHashMap to maintain insertion order for bounded eviction.
  final LinkedHashMap<String, _SeenEntry> _seenCache = LinkedHashMap();

  GossipEngine({
    required AbstractBleService ble,
    required PeerRegistry peers,
    required AesGcmService crypto,
    required PacketQueueDao queue,
    required int localShortId,
  })  : _ble = ble,
        _peers = peers,
        _crypto = crypto,
        _queue = queue,
        _localShortId = localShortId;

  // ─── Public API ───────────────────────────────────────────────────────────

  /// Entry point for the local node to **originate** a data packet (not relay).
  Future<void> originateDataPacket(BleDataPacket packet) async {
    _markSeen(packet.dedupKey);
    await _forwardDataPacket(packet);
  }

  /// Entry point for originating a chat text packet.
  Future<void> originateChatPacket(BleChatTextPacket packet) async {
    _markSeen(packet.dedupKey);
    await _forwardChatPacket(packet);
  }

  /// Called when a [BleChatTextPacket] arrives from the BLE layer.
  Future<void> onChatPacketReceived(
    BleChatTextPacket packet,
    String senderDeviceId,
  ) async {
    if (_hasSeenBefore(packet.dedupKey)) return;
    _markSeen(packet.dedupKey);
    if (!packet.canRelay) return;
    await _forwardChatPacket(packet.relay(), excludeId: senderDeviceId);
  }

  /// Called when a [BleDataPacket] arrives from the BLE layer (via a peer).
  ///
  /// Deduplicates, decrements TTL, and gossip-forwards to [kGossipFanout] random
  /// peers (excluding the sender). Safe to call concurrently.
  Future<void> onDataPacketReceived(
    BleDataPacket packet,
    String senderDeviceId,
  ) async {
    // 1. Deduplication check.
    if (_hasSeenBefore(packet.dedupKey)) return;
    _markSeen(packet.dedupKey);

    // 2. TTL check – only relay if TTL > 1 (we decrement on relay = new TTL ≥ 1).
    if (!packet.canRelay) return;

    // 3. Forward to random subset of peers (excluding original sender).
    await _forwardDataPacket(packet.relay(), excludeId: senderDeviceId);
  }

  /// Broadcasts a heartbeat or election-bid packet to ALL alive peers.
  /// These control packets do NOT go through the Store-Carry-Forward queue.
  Future<void> broadcastControlPacket(Uint8List plainBytes) async {
    final alivePeers = _peers.alivePeers;
    if (alivePeers.isEmpty) return;

    await Future.wait([
      for (final peer in alivePeers)
        _sendToPeer(peer, plainBytes).catchError((_) {/* Ignore individual send failures */}),
    ]);
  }

  // ─── Private ─────────────────────────────────────────────────────────────

  Future<void> _forwardDataPacket(
    BleDataPacket packet, {
    String? excludeId,
  }) async {
    final plainBytes = packet.toBytes();
    final targets = _peers.randomSubset(count: kGossipFanout, excludeId: excludeId);

    if (targets.isEmpty) {
      final encrypted = await _crypto.encrypt(plainBytes);
      await _queue.enqueue(
        encryptedPayload: encrypted,
        targetDeviceId: null,
        packetTypeByte: BlePacketType.data.wireValue,
        nowMs: DateTime.now().millisecondsSinceEpoch,
      );
      return;
    }

    await Future.wait([
      for (final peer in targets)
        _sendToPeer(peer, plainBytes).catchError((_) async {
          final encrypted = await _crypto.encrypt(plainBytes);
          await _queue.enqueue(
            encryptedPayload: encrypted,
            targetDeviceId: peer.deviceId,
            packetTypeByte: BlePacketType.data.wireValue,
            nowMs: DateTime.now().millisecondsSinceEpoch,
          );
        }),
    ]);
  }

  Future<void> _forwardChatPacket(
    BleChatTextPacket packet, {
    String? excludeId,
  }) async {
    final plainBytes = packet.toBytes();
    final targets = _peers.randomSubset(count: kGossipFanout, excludeId: excludeId);

    if (targets.isEmpty) {
      final encrypted = await _crypto.encrypt(plainBytes);
      await _queue.enqueue(
        encryptedPayload: encrypted,
        targetDeviceId: null,
        packetTypeByte: BlePacketType.text.wireValue,
        nowMs: DateTime.now().millisecondsSinceEpoch,
      );
      return;
    }

    await Future.wait([
      for (final peer in targets)
        _sendToPeer(peer, plainBytes).catchError((_) async {
          final encrypted = await _crypto.encrypt(plainBytes);
          await _queue.enqueue(
            encryptedPayload: encrypted,
            targetDeviceId: peer.deviceId,
            packetTypeByte: BlePacketType.text.wireValue,
            nowMs: DateTime.now().millisecondsSinceEpoch,
          );
        }),
    ]);
  }

  Future<void> _sendToPeer(PeerInfo peer, Uint8List plainBytes) =>
      _ble.sendPacket(peer.deviceId, plainBytes);

  // ─── Seen-packet cache ────────────────────────────────────────────────────

  bool _hasSeenBefore(String dedupKey) {
    final entry = _seenCache[dedupKey];
    if (entry == null) return false;
    if (entry.isExpired) {
      _seenCache.remove(dedupKey);
      return false;
    }
    return true;
  }

  void _markSeen(String dedupKey) {
    // Bounded eviction: drop the oldest 10 % when at capacity.
    if (_seenCache.length >= kSeenCacheMaxSize) {
      final evictCount = (kSeenCacheMaxSize * 0.1).ceil();
      final keysToEvict = _seenCache.keys.take(evictCount).toList();
      for (final k in keysToEvict) {
        _seenCache.remove(k);
      }
    }
    _seenCache[dedupKey] = _SeenEntry(DateTime.now().millisecondsSinceEpoch);
  }

  /// Drains the Store-Carry-Forward queue for a newly discovered peer.
  ///
  /// Called by [NetworkRepositoryWeaver] whenever a new peer comes into range.
  Future<void> drainQueueForPeer(String peerId) async {
    final pending = await _queue.dequeueForDelivery(peerId);
    for (final row in pending) {
      try {
        // Decrypt to verify integrity, then re-send (already encrypted in DB).
        await _ble.sendPacket(peerId, Uint8List.fromList(row.encryptedPayload));
        await _queue.markDelivered(row.id);
      } catch (_) {
        await _queue.incrementRetryCount(row.id);
      }
    }
  }
}

/// network_repository_weaver.dart
/// ────────────────────────────────
/// The **central coordinator** of the StageSync network stack.
///
/// All decisions about WHERE and HOW to route a data packet flow through here:
///
///   ┌─────────────────────────────────────────────────────────────┐
///   │                   NetworkRepositoryWeaver                    │
///   │                                                             │
///   │  [ScanItemCommand]                                          │
///   │       │                                                     │
///   │       ▼                                                     │
///   │  1. Persist CRDT delta to SQLite (Drift) ← ACID guarantee  │
///   │       │                                                     │
///   │       ├─── isLeader? ──► WebSocketService.send()           │
///   │       │                                                     │
///   │       └─── isFollower? ─► GossipEngine.originateDataPacket │
///   │                              │                             │
///   │                              ▼                             │
///   │                    BLE Mesh → Leader device               │
///   │                              │                             │
///   │                              ▼                             │
///   │                    Leader.WebSocketService.send()          │
///   └─────────────────────────────────────────────────────────────┘
///
/// The Weaver also acts as the **inbound dispatcher**:
///   * Heartbeats     → LeaderElectionEngine.onHeartbeatReceived()
///   * ElectionBids   → LeaderElectionEngine.onBidReceived()
///   * DataPackets    → mergeRemote() in Drift → emit ItemUpdatedEvent → relay
///   * ServerMessages → decrypt → parse → mergeRemote()
///   * AckPackets     → mark queue entry delivered
library network_repository_weaver;

import 'dart:async';
import 'dart:typed_data';

import '../ble/ble_mesh_service.dart' show BleMeshService; // Rückwärtskompatibilität
import '../ble/gossip_engine.dart';
import '../crypto/aes_gcm_service.dart';
import '../db/app_database.dart';
import '../db/dao/chat_dao.dart';
import '../db/dao/inventory_dao.dart';
import '../db/dao/packet_queue_dao.dart';
import '../isolate/isolate_messages.dart';
import '../models/ble_packet.dart';
import '../models/inventory_item_crdt.dart';
import '../platform/abstract_ble_service.dart';
import '../routing/leader_election_engine.dart';
import '../routing/peer_registry.dart';
import '../server/websocket_service.dart';

// ─────────────────────────────────────────────────────────────────────────────

class NetworkRepositoryWeaver {
  // ── Dependencies ──────────────────────────────────────────────────────────
  final AbstractBleService _ble;
  final GossipEngine _gossip;
  final WebSocketService _ws;
  final InventoryDao _inventoryDao;
  final PacketQueueDao _queueDao;
  final ChatDao _chatDao;
  final LeaderElectionEngine _election;
  final AesGcmService _crypto;
  final PeerRegistry _peers;

  /// Callback zum Emittieren von Events an die UI-Seite.
  /// Auf native: `(e) => mainSendPort.send(e)`
  /// Auf Web: `(e) => streamController.add(e)`
  final void Function(NetworkEvent) _emitEvent;

  /// This device's full unique identifier (UUID string).
  final String _localDeviceId;
  final int _localShortId;

  // ── Streams & subscriptions ───────────────────────────────────────────────
  StreamSubscription<IncomingBlePacket>? _bleSub;
  Timer? _statusBroadcastTimer;
  Timer? _maintenanceTimer;

  NetworkRepositoryWeaver({
    required AbstractBleService ble,
    required GossipEngine gossip,
    required WebSocketService ws,
    required InventoryDao inventoryDao,
    required PacketQueueDao queueDao,
    required ChatDao chatDao,
    required LeaderElectionEngine election,
    required AesGcmService crypto,
    required PeerRegistry peers,
    required void Function(NetworkEvent) emitEvent,
    required String localDeviceId,
    required int localShortId,
  })  : _ble = ble,
        _gossip = gossip,
        _ws = ws,
        _inventoryDao = inventoryDao,
        _queueDao = queueDao,
        _chatDao = chatDao,
        _election = election,
        _crypto = crypto,
        _peers = peers,
        _emitEvent = emitEvent,
        _localDeviceId = localDeviceId,
        _localShortId = localShortId;

  // ─── Lifecycle ────────────────────────────────────────────────────────────

  Future<void> start() async {
    // 1. Subscribe to peer change events – drain queue for new peers.
    _peers.addListener(_onPeerChanged);

    // 2. Subscribe to all incoming BLE packets.
    _bleSub = _ble.onPacketReceived.listen(_onIncomingBlePacket);

    // 3. Start BLE scanning and advertising.
    await _ble.start();

    // 4. Start election engine (triggers first election after 500 ms).
    await _election.start();

    // 5. Periodic status broadcast to the UI isolate (every 5 s).
    _statusBroadcastTimer = Timer.periodic(
      const Duration(seconds: 5),
      (_) => _emitStatus(),
    );

    // 6. Periodic DB maintenance (every 10 min).
    _maintenanceTimer = Timer.periodic(
      const Duration(minutes: 10),
      (_) => _runMaintenance(),
    );
  }

  Future<void> stop() async {
    _statusBroadcastTimer?.cancel();
    _maintenanceTimer?.cancel();
    await _bleSub?.cancel();
    await _election.stop();
    await _ble.stop();
    await _ws.disconnect();
    _peers.removeListener(_onPeerChanged);
  }

  // ─── Command handler (called by the isolate event loop) ──────────────────

  Future<void> handleCommand(NetworkCommand command) async {
    switch (command) {
      case ScanItemCommand():
        await _handleScanItem(command);
      case SendChatMessageCommand():
        await _handleSendChat(command);
      case ConnectToServerCommand():
        await _handleConnectToServer(command);
      case ForceElectionCommand():
        await _election.startElectionRound();
      case QueryStatusCommand():
        await _emitStatus();
      case ShutdownCommand():
        await stop();
    }
  }

  // ─── Outbound: Chat message ───────────────────────────────────────────────

  Future<void> _handleSendChat(SendChatMessageCommand cmd) async {
    final nowMs = DateTime.now().millisecondsSinceEpoch;
    final msgId = _randomUint32();
    final label = _localDeviceId.length > 8
        ? '…${_localDeviceId.substring(_localDeviceId.length - 8)}'
        : _localDeviceId;

    // 1. Persist locally first (ACID guarantee).
    await _chatDao.insertMessage(
      messageId: '$_localShortId:$msgId',
      senderDeviceId: _localDeviceId,
      senderShortId: _localShortId,
      senderLabel: label,
      content: cmd.content,
      timestampMs: nowMs,
      isMine: true,
    );

    // 2. Emit immediately to UI.
    _eventPort.send(ChatMessageReceivedEvent(
      messageId: '$_localShortId:$msgId',
      senderDeviceId: _localDeviceId,
      senderShortLabel: label,
      content: cmd.content,
      timestampMs: nowMs,
      isMine: true,
    ));

    // 3. Build and gossip a BleChatTextPacket.
    final packet = BleChatTextPacket.create(
      sourceDeviceShortId: _localShortId,
      messageId: msgId,
      text: cmd.content,
    );
    await _gossip.originateChatPacket(packet);
  }

  // ─── Outbound: Local scan → Network ──────────────────────────────────────
  /// Handles a user-initiated inventory scan:
  ///   1. Build CRDT from scan data.
  ///   2. Persist atomically in SQLite.
  ///   3. Route: leader → WebSocket, follower → BLE Mesh via Gossip.
  Future<void> _handleScanItem(ScanItemCommand cmd) async {
    // Build or merge with existing CRDT.
    final existing = await _inventoryDao.getByItemId(cmd.itemId);
    late InventoryItemCrdt crdt;

    if (existing == null) {
      crdt = InventoryItemCrdt.create(
        itemId: cmd.itemId,
        deviceId: _localDeviceId,
        deviceShortId: _localShortId,
        statusId: cmd.statusId,
        locationTag: cmd.locationTag,
        wallClockMs: cmd.timestampMs,
      );
    } else {
      final localCrdt = InventoryItemCrdt.fromJsonString(existing.crdtJson);
      crdt = localCrdt.withStatusUpdate(
        newStatusId: cmd.statusId,
        deviceId: _localDeviceId,
        deviceShortId: _localShortId,
        wallClockMs: cmd.timestampMs,
      );
      if (cmd.locationTag != null) {
        crdt = crdt.withLocationUpdate(
          newLocation: cmd.locationTag,
          deviceId: _localDeviceId,
          deviceShortId: _localShortId,
          wallClockMs: cmd.timestampMs,
        );
      }
    }

    // ACID persist before any network operation.
    await _inventoryDao.upsertCrdt(crdt);

    // Emit immediate UI feedback.
    _eventPort.send(ItemUpdatedEvent(
      itemId: crdt.itemId,
      statusId: crdt.status.value,
      locationTag: crdt.location.value,
      sourceDeviceId: _localDeviceId,
      timestampMs: cmd.timestampMs,
      isSyncedToServer: false,
    ));

    // Route the update.
    await _routeOutboundCrdt(crdt, cmd.timestampMs);
  }

  /// Decides whether to push a CRDT delta directly via [WebSocketService]
  /// (leader path) or relay it into the BLE mesh via [GossipEngine] (follower).
  Future<void> _routeOutboundCrdt(InventoryItemCrdt crdt, int timestampMs) async {
    if (_election.isLeader) {
      // ── Leader path: send directly to server ────────────────────────────
      if (_ws.isConnected) {
        final jsonBytes = Uint8List.fromList(crdt.toJsonString().codeUnits);
        final encrypted = await _crypto.encrypt(jsonBytes);
        _ws.send(encrypted);
      } else {
        // Leader but server unreachable: also propagate via BLE so that if
        // another device regains connectivity they can relay it.
        await _gossipDataPacket(crdt, timestampMs);
      }
    } else {
      // ── Follower path: gossip into BLE mesh towards leader ───────────────
      await _gossipDataPacket(crdt, timestampMs);
    }
  }

  Future<void> _gossipDataPacket(InventoryItemCrdt crdt, int timestampMs) async {
    final packet = BleDataPacket.create(
      sourceDeviceShortId: _localShortId,
      itemShortId: shortIdFromString(crdt.itemId),
      statusId: crdt.status.value,
      timestampSec: timestampMs ~/ 1000,
    );
    await _gossip.originateDataPacket(packet);
  }

  // ─── Outbound: Server connection (leader only) ────────────────────────────

  Future<void> _handleConnectToServer(ConnectToServerCommand cmd) async {
    if (!_election.isLeader) return; // Followers ignore this command.
    await _ws.connect(cmd.serverUrl);
  }

  // ─── Inbound: BLE packet dispatcher ─────────────────────────────────────

  Future<void> _onIncomingBlePacket(IncomingBlePacket incoming) async {
    final packet = incoming.packet;
    final sender = incoming.senderDeviceId;

    switch (packet) {
      case BleDataPacket():
        await _handleIncomingDataPacket(packet, sender);

      case BleHeartbeatPacket():
        _election.onHeartbeatReceived(sender);

      case BleElectionBidPacket():
        _election.onBidReceived(sender, packet.score);
        // Relay election bids further so all nodes in the mesh receive them.
        if (packet.header.ttl > 1) {
          final relayed = Uint8List.fromList(
            BleElectionBidPacket(
              header: packet.header.withDecrementedTtl(),
              score: packet.score,
            ).toBytes(),
          );
          await _gossip.broadcastControlPacket(relayed);
        }

      case BleAckPacket():
        await _queueDao.markDelivered(packet.ackedPacketShortId);

      case BleChatTextPacket():
        await _handleIncomingChatPacket(packet, sender);

      default:
        break; // Unknown packet type – discard.
    }
  }

  Future<void> _handleIncomingDataPacket(
    BleDataPacket packet,
    String senderDeviceId,
  ) async {
    await _gossip.onDataPacketReceived(packet, senderDeviceId);
    if (_election.isLeader && _ws.isConnected) {
      final encrypted = await _crypto.encrypt(Uint8List.fromList(packet.toBytes()));
      _ws.send(encrypted);
    }
    _eventPort.send(ItemUpdatedEvent(
      itemId: packet.itemShortId.toRadixString(16),
      statusId: packet.statusId,
      locationTag: null,
      sourceDeviceId: senderDeviceId,
      timestampMs: packet.timestampSec * 1000,
      isSyncedToServer: _election.isLeader && _ws.isConnected,
    ));
  }

  Future<void> _handleIncomingChatPacket(
    BleChatTextPacket packet,
    String senderDeviceId,
  ) async {
    final dedupKey = '${packet.header.sourceDeviceShortId}:${packet.messageId}';

    // Relay further if TTL allows.
    await _gossip.onChatPacketReceived(packet, senderDeviceId);

    final nowMs = DateTime.now().millisecondsSinceEpoch;
    final label = senderDeviceId.length > 8
        ? '…${senderDeviceId.substring(senderDeviceId.length - 8)}'
        : senderDeviceId;

    // Persist (insertOnConflictUpdate = idempotent).
    await _chatDao.insertMessage(
      messageId: dedupKey,
      senderDeviceId: senderDeviceId,
      senderShortId: packet.header.sourceDeviceShortId,
      senderLabel: label,
      content: packet.text,
      timestampMs: nowMs,
      isMine: false,
    );

    // Notify UI.
    _eventPort.send(ChatMessageReceivedEvent(
      messageId: dedupKey,
      senderDeviceId: senderDeviceId,
      senderShortLabel: label,
      content: packet.text,
      timestampMs: nowMs,
      isMine: false,
    ));
  }

  // ─── Inbound: Server → Local (leader receives, relays to followers) ───────

  void _onServerMessage(Uint8List encrypted) async {
    try {
      final plainBytes = await _crypto.decrypt(encrypted);
      final jsonString = String.fromCharCodes(plainBytes);
      final remoteCrdt = InventoryItemCrdt.fromJsonString(jsonString);

      // Merge with local state and persist.
      final merged = await _inventoryDao.mergeRemote(remoteCrdt);
      await _inventoryDao.markSynced(merged.itemId);

      // Broadcast the updated CRDT to all BLE peers so followers get it.
      final updatePacket = BleDataPacket.create(
        sourceDeviceShortId: _localShortId,
        itemShortId: shortIdFromString(merged.itemId),
        statusId: merged.status.value,
        timestampSec: merged.status.wallClockMs ~/ 1000,
      );
      await _gossip.originateDataPacket(updatePacket);

      // Notify the UI.
      _eventPort.send(ItemUpdatedEvent(
        itemId: merged.itemId,
        statusId: merged.status.value,
        locationTag: merged.location.value,
        sourceDeviceId: 'server',
        timestampMs: merged.status.wallClockMs,
        isSyncedToServer: true,
      ));
    } catch (_) {
      // Malformed or unauthenticated server message – discard.
    }
  }

  // ─── Peer change handler (Store-Carry-Forward drain) ─────────────────────

  void _onPeerChanged(PeerInfo peer, bool isOnline) {
    _eventPort.send(PeerDiscoveredEvent(
      deviceId: peer.deviceId,
      rssi: peer.rssi,
      isOnline: isOnline,
    ));

    if (isOnline) {
      // Drain the queue for the newly available peer.
      _gossip.drainQueueForPeer(peer.deviceId).ignore();
    }
  }

  // ─── Leadership change handler ────────────────────────────────────────────

  void handleLeadershipChange({
    required String newLeaderId,
    required bool isThisDeviceLeader,
    required int winningScore,
  }) {
    _eventPort.send(LeaderChangedEvent(
      newLeaderDeviceId: newLeaderId,
      isThisDeviceLeader: isThisDeviceLeader,
      leaderScore: winningScore,
    ));
  }

  // ─── Periodic status event ────────────────────────────────────────────────

  Future<void> _emitStatus() async {
    final pending = await _queueDao.pendingCount();
    final breakdown = await _election.computeScoreBreakdown();

    final peerInfos = _peers.alivePeers.map((p) => PeerStatusInfo(
          deviceId: p.deviceId,
          deviceShortId: p.deviceShortId,
          rssi: p.rssi,
          electionScore: p.electionScore,
          isLeader: p.isLeader,
          hasInternet: p.hasInternet,
          lastSeenMs: p.lastSeenMs,
        )).toList()
          ..sort((a, b) => b.rssi.compareTo(a.rssi)); // Sort by signal strength

    _eventPort.send(NetworkStatusEvent(
      connectedPeerCount: _peers.aliveCount,
      pendingQueuedPackets: pending,
      hasServerConnection: _ws.isConnected,
      currentLeaderId: _election.currentLeaderId,
      localElectionScore: breakdown.total,
      syncStatus: _determineSyncStatus(),
      peers: peerInfos,
      scoreBreakdown: breakdown,
    ));
  }

  // ─── Helper: random uint32 for message IDs ────────────────────────────────
  static int _randomUint32() {
    final r = DateTime.now().microsecondsSinceEpoch & 0xFFFFFFFF;
    return r;
  }

  NetworkSyncStatus _determineSyncStatus() {
    if (_ws.isConnected) return NetworkSyncStatus.syncing;
    if (_peers.aliveCount > 0) return NetworkSyncStatus.meshOnly;
    return NetworkSyncStatus.offline;
  }

  // ─── DB maintenance ───────────────────────────────────────────────────────

  Future<void> _runMaintenance() async {
    await _queueDao.purgeDelivered();
    await _queueDao.purgeStale();
  }
}

/// aes_gcm_service.dart
/// ─────────────────────
/// AES-256-GCM symmetric encryption layer for all BLE Mesh broadcast packets.
///
/// ## Security Model
/// All devices in a theater production share a single 256-bit symmetric key
/// that is compiled into the application (or loaded from a secure key-store at
/// first launch). This is appropriate for a **closed, private network** where
/// all participants are trusted staff. The key prevents passive eavesdropping
/// and packet injection by non-StageSync devices operating nearby BLE radios.
///
/// ## Wire Format (after [encrypt])
/// ┌──────────────┬───────────────────┬─────────────────┐
/// │  Nonce 12 B  │  Ciphertext N B   │  Auth-Tag 16 B  │
/// └──────────────┴───────────────────┴─────────────────┘
/// Total overhead: +28 bytes per packet.
///
/// ## Usage
/// ```dart
/// final svc = AesGcmService.fromHexKey('...');
/// final ciphertext = await svc.encrypt(plaintext);
/// final plaintext  = await svc.decrypt(ciphertext); // throws on tamper
/// ```
library aes_gcm_service;

import 'dart:typed_data';

import 'package:cryptography/cryptography.dart';

// ─────────────────────────────────────────────────────────────────────────────
// Production shared key – REPLACE with your actual secret before shipping.
// In a real deployment, load this from a secure key-store (Android Keystore /
// iOS Secure Enclave) or derive it via ECDH + HKDF at pairing time.
// The key below is 32 bytes = 256 bits, AES-256 compliant.
// ─────────────────────────────────────────────────────────────────────────────

/// Hex-encoded 256-bit production key.  ← CHANGE BEFORE DEPLOYMENT
const String kStageSyncSharedKeyHex =
    'a3f8c2e1d4b7906a12345678abcdef0123456789abcdef0123456789abcdef01';

// ─────────────────────────────────────────────────────────────────────────────

class AesGcmService {
  static const int _nonceLength = 12; // GCM standard nonce size
  static const int _macLength = 16;   // GCM authentication tag size

  final AesGcm _algorithm;
  final SecretKey _secretKey;

  /// Private constructor – use factories below.
  AesGcmService._(this._algorithm, this._secretKey);

  // ─── Factories ──────────────────────────────────────────────────────────

  /// Construct from a 64-character lower-case hex string (32 bytes / 256 bits).
  static Future<AesGcmService> fromHexKey(String hexKey) async {
    assert(hexKey.length == 64, 'AES-256 key must be 64 hex chars (32 bytes)');
    final keyBytes = _hexToBytes(hexKey);
    final algorithm = AesGcm.with256bits();
    final secretKey = await algorithm.newSecretKeyFromBytes(keyBytes);
    return AesGcmService._(algorithm, secretKey);
  }

  /// Convenience factory using the compiled-in production key.
  static Future<AesGcmService> withProductionKey() =>
      fromHexKey(kStageSyncSharedKeyHex);

  // ─── Public API ─────────────────────────────────────────────────────────

  /// Encrypts [plaintext] using AES-256-GCM with a fresh random nonce.
  ///
  /// Returns `nonce (12 B) ‖ ciphertext (N B) ‖ auth-tag (16 B)`.
  Future<Uint8List> encrypt(Uint8List plaintext) async {
    final secretBox = await _algorithm.encrypt(
      plaintext,
      secretKey: _secretKey,
      // nonce = null → the library generates a cryptographically random nonce
    );

    // Concatenate: nonce || ciphertext || mac for compact wire encoding.
    return Uint8List.fromList([
      ...secretBox.nonce,
      ...secretBox.cipherText,
      ...secretBox.mac.bytes,
    ]);
  }

  /// Decrypts and authenticates a packet produced by [encrypt].
  ///
  /// Throws [SecretBoxAuthenticationError] if the authentication tag is invalid
  /// (packet was tampered with or key mismatch). Callers MUST handle this.
  Future<Uint8List> decrypt(Uint8List encryptedBytes) async {
    if (encryptedBytes.length < _nonceLength + _macLength) {
      throw FormatException(
        'Encrypted packet too short: ${encryptedBytes.length} bytes '
        '(minimum ${_nonceLength + _macLength})',
      );
    }

    final nonce = encryptedBytes.sublist(0, _nonceLength);
    final cipherText =
        encryptedBytes.sublist(_nonceLength, encryptedBytes.length - _macLength);
    final mac = encryptedBytes.sublist(encryptedBytes.length - _macLength);

    final secretBox = SecretBox(cipherText, nonce: nonce, mac: Mac(mac));
    final plaintext = await _algorithm.decrypt(secretBox, secretKey: _secretKey);
    return Uint8List.fromList(plaintext);
  }

  // ─── Helpers ────────────────────────────────────────────────────────────

  static Uint8List _hexToBytes(String hex) {
    final result = Uint8List(hex.length ~/ 2);
    for (int i = 0; i < result.length; i++) {
      result[i] = int.parse(hex.substring(i * 2, i * 2 + 2), radix: 16);
    }
    return result;
  }
}

/// app_database.dart
/// ──────────────────
/// Drift (SQLite) schema for StageSync.
///
/// Tables:
///   [InventoryItems]  – LWW-CRDT state of every inventory item.
///   [PacketQueue]     – Store-Carry-Forward outbound packet queue.
///   [PeerTable]       – Known BLE peer devices and their election scores.
///
/// Run code generation after editing this file:
///   flutter pub run build_runner build --delete-conflicting-outputs
library app_database;

import 'dart:io';

import 'package:drift/drift.dart';
import 'package:drift/native.dart';
import 'package:path/path.dart' as p;
import 'package:path_provider/path_provider.dart';

part 'app_database.g.dart';

// ─────────────────────────────────────────────────────────────────────────────
// Table: InventoryItems
// ─────────────────────────────────────────────────────────────────────────────

/// Stores the full CRDT state of a single inventory item.
/// The [crdtJson] column contains the serialised [InventoryItemCrdt] including
/// both LWW fields and their vector clocks.
class InventoryItems extends Table {
  /// Auto-increment primary key (local DB-only; not distributed).
  IntColumn get id => integer().autoIncrement()();

  /// Application-level globally unique item ID (QR value / UUID string).
  TextColumn get itemId => text().unique()();

  /// Serialised [InventoryItemCrdt] JSON – single source of truth.
  TextColumn get crdtJson => text()();

  /// StatusId cached at the DB row level for fast SQL filtering.
  IntColumn get statusId => integer()();

  /// Location tag cached for fast SQL querying.
  TextColumn get locationTag => text().nullable()();

  /// Wall-clock ms of the most recent local write (for quick ordering).
  IntColumn get lastUpdatedMs => integer()();

  /// DeviceID that made the most recent write to this row.
  TextColumn get sourceDeviceId => text()();

  /// True once the central server acknowledged this item's current CRDT state.
  BoolColumn get isSyncedToServer =>
      boolean().withDefault(const Constant(false))();
}

// ─────────────────────────────────────────────────────────────────────────────
// Table: PacketQueue  (Store-Carry-Forward)
// ─────────────────────────────────────────────────────────────────────────────

/// Persists outbound BLE packets that could not yet be delivered because no
/// peers were in range. On peer discovery the queue is drained automatically.
class PacketQueue extends Table {
  IntColumn get id => integer().autoIncrement()();

  /// Raw ENCRYPTED bytes of the BLE packet.
  BlobColumn get encryptedPayload => blob()();

  /// Target peer device ID; null means broadcast to all reachable peers.
  TextColumn get targetDeviceId => text().nullable()();

  /// PacketType byte (mirrors [BlePacketType.wireValue]) for fast filtering.
  IntColumn get packetTypeByte => integer()();

  /// Creation timestamp (ms) – used for TTL expiration of stale queue entries.
  IntColumn get createdAtMs => integer()();

  /// Number of delivery attempts made so far.
  IntColumn get retryCount => integer().withDefault(const Constant(0))();

  /// Delivered successfully – retained briefly for idempotent deduplication.
  BoolColumn get isDelivered => boolean().withDefault(const Constant(false))();
}

// ─────────────────────────────────────────────────────────────────────────────
// Table: PeerTable
// ─────────────────────────────────────────────────────────────────────────────

/// Tracks all known BLE peers discovered during the current session.
/// This table is ephemeral (cleared on cold start) but persisted in SQLite
/// so the network isolate can query it efficiently via Drift.
class PeerTable extends Table {
  /// Full device ID string (UUID or platform BLE device ID).
  TextColumn get deviceId => text()();

  /// Pre-computed uint16 short ID (lower 16 bits of djb2 hash of deviceId).
  IntColumn get deviceShortId => integer()();

  /// Most recently received election score from this peer.
  IntColumn get electionScore => integer().withDefault(const Constant(0))();

  /// Last received RSSI value (dBm, negative).
  IntColumn get rssi => integer().withDefault(const Constant(-100))();

  /// Epoch ms of the most recent contact (scan, heartbeat, or data packet).
  IntColumn get lastSeenMs => integer()();

  /// True if this peer is currently considered the network leader.
  BoolColumn get isLeader => boolean().withDefault(const Constant(false))();

  /// True if this peer is believed to have an active internet connection.
  BoolColumn get hasInternet => boolean().withDefault(const Constant(false))();

  @override
  Set<Column> get primaryKey => {deviceId};
}

// ─────────────────────────────────────────────────────────────────────────────
// Table: ChatMessages
// ─────────────────────────────────────────────────────────────────────────────

/// Persists all chat messages seen or originated by this device.
class ChatMessages extends Table {
  IntColumn get id => integer().autoIncrement()();

  /// UUID string that uniquely identifies the message across the whole mesh.
  TextColumn get messageId => text().unique()();

  /// Full device ID of the author.
  TextColumn get senderDeviceId => text()();

  /// uint16 short ID of the sender (for compact display).
  IntColumn get senderShortId => integer()();

  /// Human-readable label derived from senderDeviceId.
  TextColumn get senderLabel => text()();

  /// UTF-8 text content.
  TextColumn get content => text()();

  /// Wall-clock ms when the message was created by the sender.
  IntColumn get timestampMs => integer()();

  /// True if this device originated the message.
  BoolColumn get isMine => boolean().withDefault(const Constant(false))();
}

// ─────────────────────────────────────────────────────────────────────────────
// Database Class
// ─────────────────────────────────────────────────────────────────────────────

@DriftDatabase(tables: [InventoryItems, PacketQueue, PeerTable, ChatMessages])
class AppDatabase extends _$AppDatabase {
  AppDatabase(super.e);

  @override
  MigrationStrategy get migration => MigrationStrategy(
        onCreate: (m) async {
          await m.createAll();
        },
        onUpgrade: (m, from, to) async {
          if (from < 2) {
            await m.createTable(chatMessages);
          }
        },
      );

  @override
  int get schemaVersion => 2;

  // ─── Convenience: open on the main isolate (path_provider available) ────

  /// Opens the database in the application documents directory.
  /// Must be called from the main isolate (uses path_provider).
  static Future<String> resolveDatabasePath() async {
    final dir = await getApplicationDocumentsDirectory();
    return p.join(dir.path, 'stagesync.db');
  }

  /// Opens the database given an absolute file [path].
  /// Safe to call from any isolate once the [path] has been resolved.
  static AppDatabase openAtPath(String path) {
    return AppDatabase(NativeDatabase(File(path), logStatements: false));
  }
}

/// chat_dao.dart
/// ──────────────
/// Data-Access Object for the [ChatMessages] table.
library chat_dao;

import 'package:drift/drift.dart';

import '../app_database.dart';

class ChatDao {
  final AppDatabase _db;
  ChatDao(this._db);

  // ─── Write ───────────────────────────────────────────────────────────────

  /// Persists a chat message. Silently ignored if [messageId] already exists
  /// (guarantees idempotent storage for gossip-relayed duplicates).
  Future<void> insertMessage({
    required String messageId,
    required String senderDeviceId,
    required int senderShortId,
    required String senderLabel,
    required String content,
    required int timestampMs,
    required bool isMine,
  }) async {
    await _db.into(_db.chatMessages).insertOnConflictUpdate(
          ChatMessagesCompanion.insert(
            messageId: messageId,
            senderDeviceId: senderDeviceId,
            senderShortId: senderShortId,
            senderLabel: senderLabel,
            content: content,
            timestampMs: timestampMs,
            isMine: Value(isMine),
          ),
        );
  }

  // ─── Read ─────────────────────────────────────────────────────────────────

  /// Returns the last [limit] messages ordered by timestamp ascending.
  Future<List<ChatMessage>> getRecentMessages({int limit = 100}) =>
      (_db.select(_db.chatMessages)
            ..orderBy([(t) => OrderingTerm.asc(t.timestampMs)])
            ..limit(limit))
          .get();

  // ─── Streaming ────────────────────────────────────────────────────────────

  /// Emits a fresh list whenever the chat table changes.
  Stream<List<ChatMessage>> watchMessages({int limit = 200}) =>
      (_db.select(_db.chatMessages)
            ..orderBy([(t) => OrderingTerm.asc(t.timestampMs)])
            ..limit(limit))
          .watch();

  // ─── Maintenance ──────────────────────────────────────────────────────────

  /// Removes messages older than [maxAgeMs] (default 24 h).
  Future<int> purgeOld({int maxAgeMs = 24 * 60 * 60 * 1000}) async {
    final cutoff = DateTime.now().millisecondsSinceEpoch - maxAgeMs;
    return (_db.delete(_db.chatMessages)
          ..where((t) => t.timestampMs.isSmallerThanValue(cutoff)))
        .go();
  }
}

/// inventory_dao.dart
/// ───────────────────
/// Data-Access Object for the [InventoryItems] table.
/// All CRDT merge logic lives in [InventoryItemCrdt]; this DAO is purely
/// concerned with atomic SQLite persistence and efficient querying.
library inventory_dao;

import 'package:drift/drift.dart';

import '../app_database.dart';
import '../../models/inventory_item_crdt.dart';

class InventoryDao {
  final AppDatabase _db;

  InventoryDao(this._db);

  // ─── Read ────────────────────────────────────────────────────────────────

  /// Returns all inventory items ordered by most recently updated.
  Future<List<InventoryItem>> getAllItems() =>
      (_db.select(_db.inventoryItems)
            ..orderBy([(t) => OrderingTerm.desc(t.lastUpdatedMs)]))
          .get();

  /// Returns a single item by its application-level [itemId], or null.
  Future<InventoryItem?> getByItemId(String itemId) =>
      (_db.select(_db.inventoryItems)
            ..where((t) => t.itemId.equals(itemId)))
          .getSingleOrNull();

  /// Returns all items not yet acknowledged by the central server.
  Future<List<InventoryItem>> getPendingSyncItems() =>
      (_db.select(_db.inventoryItems)
            ..where((t) => t.isSyncedToServer.equals(false)))
          .get();

  // ─── Write ───────────────────────────────────────────────────────────────

  /// Persists or updates a [InventoryItemCrdt] in a single atomic operation.
  ///
  /// Uses Drift's [insertOnConflictUpdate] so this call is safe to call
  /// multiple times with the same [crdt] without duplicate rows.
  ///
  /// Returns the row-level DB primary key.
  Future<int> upsertCrdt(InventoryItemCrdt crdt) async {
    return _db.into(_db.inventoryItems).insertOnConflictUpdate(
          InventoryItemsCompanion.insert(
            itemId: crdt.itemId,
            crdtJson: crdt.toJsonString(),
            statusId: crdt.status.value,
            locationTag: Value(crdt.location.value),
            lastUpdatedMs: Value(
              crdt.status.wallClockMs > crdt.location.wallClockMs
                  ? crdt.status.wallClockMs
                  : crdt.location.wallClockMs,
            ),
            sourceDeviceId: Value(crdt.status.ownerShortId.toString()),
          ),
        );
  }

  /// Merges a remote [InventoryItemCrdt] with the local copy (if any).
  ///
  /// Algorithm:
  ///   1. Load current local state from DB.
  ///   2. Call [InventoryItemCrdt.merge] → produces the merged winner.
  ///   3. Persist the merged state atomically.
  ///   4. Return the merged CRDT (so the caller can emit an [ItemUpdatedEvent]).
  ///
  /// This entire sequence runs inside a Drift transaction to prevent races.
  Future<InventoryItemCrdt> mergeRemote(InventoryItemCrdt remote) async {
    return _db.transaction<InventoryItemCrdt>(() async {
      final existing = await getByItemId(remote.itemId);

      InventoryItemCrdt merged;
      if (existing == null) {
        // First time we see this item – remote state is authoritative.
        merged = remote;
      } else {
        final local = InventoryItemCrdt.fromJsonString(existing.crdtJson);
        merged = local.merge(remote);
      }

      await upsertCrdt(merged);
      return merged;
    });
  }

  /// Marks an item as successfully synced to the central server.
  Future<void> markSynced(String itemId) async {
    await (_db.update(_db.inventoryItems)
          ..where((t) => t.itemId.equals(itemId)))
        .write(const InventoryItemsCompanion(isSyncedToServer: Value(true)));
  }

  /// Marks all items as unsynced (e.g. after a server reconnection where we
  /// need to replay the full local state).
  Future<void> markAllUnsynced() async {
    await _db.update(_db.inventoryItems).write(
          const InventoryItemsCompanion(isSyncedToServer: Value(false)),
        );
  }

  // ─── Streaming ───────────────────────────────────────────────────────────

  /// Emits a fresh list every time the [InventoryItems] table changes.
  /// The UI can consume this via a Riverpod StreamProvider for live updates.
  Stream<List<InventoryItem>> watchAllItems() =>
      (_db.select(_db.inventoryItems)
            ..orderBy([(t) => OrderingTerm.desc(t.lastUpdatedMs)]))
          .watch();
}

/// packet_queue_dao.dart
/// ──────────────────────
/// Data-Access Object for the [PacketQueue] table.
///
/// Implements the **Store-Carry-Forward** pattern:
///   1. Every outbound BLE packet is [enqueue]d atomically BEFORE any send
///      attempt. This guarantees no data loss even if the app is killed mid-
///      transmission.
///   2. When a peer is in range, [dequeueForDelivery] returns pending packets
///      for that target (or broadcast packets for any peer).
///   3. On successful delivery, [markDelivered] is called atomically.
///   4. [purgeDelivered] periodically cleans up old delivered rows.
///   5. [purgeStale] removes packets whose creation time exceeds [maxAgeMs]
///      (prevents unbounded queue growth during extended offline periods).
library packet_queue_dao;

import 'package:drift/drift.dart';

import '../app_database.dart';

/// Maximum age of a queued packet before it is discarded (12 hours).
const int kPacketMaxAgeMs = 12 * 60 * 60 * 1000;

/// Maximum queue depth – oldest excess entries are dropped to bound memory.
const int kPacketQueueMaxDepth = 500;

class PacketQueueDao {
  final AppDatabase _db;
  PacketQueueDao(this._db);

  // ─── Enqueue ─────────────────────────────────────────────────────────────

  /// Persists [encryptedPayload] atomically. Returns the new row ID.
  ///
  /// [targetDeviceId] is null for broadcast packets (delivered to whoever
  /// comes into range next).
  Future<int> enqueue({
    required List<int> encryptedPayload,
    String? targetDeviceId,
    required int packetTypeByte,
    required int nowMs,
  }) async {
    // Enforce queue depth limit: remove oldest undelivered entries first.
    await _evictIfOverDepth();

    return _db.into(_db.packetQueue).insert(
          PacketQueueCompanion.insert(
            encryptedPayload: encryptedPayload,
            targetDeviceId: Value(targetDeviceId),
            packetTypeByte: packetTypeByte,
            createdAtMs: nowMs,
          ),
        );
  }

  // ─── Dequeue ─────────────────────────────────────────────────────────────

  /// Returns all pending (not yet delivered) packets that should be sent to
  /// [peerId]: those specifically targeted at [peerId] PLUS any broadcasts.
  ///
  /// Ordered by creation time (oldest first – FIFO delivery).
  Future<List<PacketQueueData>> dequeueForDelivery(String peerId) async {
    final nowMs = DateTime.now().millisecondsSinceEpoch;
    final cutoff = nowMs - kPacketMaxAgeMs;

    return (_db.select(_db.packetQueue)
          ..where(
            (t) =>
                t.isDelivered.equals(false) &
                t.createdAtMs.isBiggerThanValue(cutoff) &
                (t.targetDeviceId.equals(peerId) | t.targetDeviceId.isNull()),
          )
          ..orderBy([(t) => OrderingTerm.asc(t.createdAtMs)]))
        .get();
  }

  /// Returns all broadcast packets pending delivery (used on leader election
  /// to flush queue towards all newly known peers).
  Future<List<PacketQueueData>> dequeueBroadcastPending() async {
    final nowMs = DateTime.now().millisecondsSinceEpoch;
    final cutoff = nowMs - kPacketMaxAgeMs;

    return (_db.select(_db.packetQueue)
          ..where(
            (t) =>
                t.isDelivered.equals(false) &
                t.targetDeviceId.isNull() &
                t.createdAtMs.isBiggerThanValue(cutoff),
          )
          ..orderBy([(t) => OrderingTerm.asc(t.createdAtMs)]))
        .get();
  }

  // ─── Delivery confirmation ────────────────────────────────────────────────

  /// Marks a specific packet as successfully delivered.
  /// Also increments the retry counter (idempotent if called multiple times).
  Future<void> markDelivered(int rowId) async {
    await (_db.update(_db.packetQueue)..where((t) => t.id.equals(rowId)))
        .write(const PacketQueueCompanion(isDelivered: Value(true)));
  }

  /// Increments the retry counter for a packet that failed to deliver.
  Future<void> incrementRetryCount(int rowId) async {
    // Drift doesn't directly support increment; use a custom update.
    await _db.customUpdate(
      'UPDATE packet_queue SET retry_count = retry_count + 1 WHERE id = ?',
      variables: [Variable.withInt(rowId)],
      updates: {_db.packetQueue},
    );
  }

  // ─── Maintenance ─────────────────────────────────────────────────────────

  /// Deletes all packets marked as delivered. Call this periodically (e.g.
  /// every 10 minutes) to keep the database lean.
  Future<int> purgeDelivered() async {
    return (_db.delete(_db.packetQueue)
          ..where((t) => t.isDelivered.equals(true)))
        .go();
  }

  /// Deletes packets older than [kPacketMaxAgeMs] that were never delivered.
  /// These are considered permanently lost (peer never came into range).
  Future<int> purgeStale() async {
    final cutoff =
        DateTime.now().millisecondsSinceEpoch - kPacketMaxAgeMs;
    return (_db.delete(_db.packetQueue)
          ..where(
            (t) => t.createdAtMs.isSmallerThanValue(cutoff),
          ))
        .go();
  }

  /// Returns the count of pending (undelivered, non-stale) queued packets.
  Future<int> pendingCount() async {
    final nowMs = DateTime.now().millisecondsSinceEpoch;
    final cutoff = nowMs - kPacketMaxAgeMs;
    final result = await _db.customSelect(
      'SELECT COUNT(*) AS cnt FROM packet_queue '
      'WHERE is_delivered = 0 AND created_at_ms > ?',
      variables: [Variable.withInt(cutoff)],
    ).getSingle();
    return result.read<int>('cnt');
  }

  // ─── Private ─────────────────────────────────────────────────────────────

  /// Removes the oldest undelivered entries when queue depth exceeds limit.
  Future<void> _evictIfOverDepth() async {
    final count = await pendingCount();
    if (count >= kPacketQueueMaxDepth) {
      final excess = count - kPacketQueueMaxDepth + 1;
      // Delete the oldest [excess] undelivered entries.
      await _db.customUpdate(
        'DELETE FROM packet_queue WHERE id IN '
        '(SELECT id FROM packet_queue WHERE is_delivered = 0 '
        'ORDER BY created_at_ms ASC LIMIT ?)',
        variables: [Variable.withInt(excess)],
        updates: {_db.packetQueue},
      );
    }
  }
}

