// db_connector_native.dart
// ─────────────────────────
// Öffnet eine SQLite-Datenbank via dart:ffi / sqlite3 (Android, iOS, Windows,
// macOS, Linux). Wird nur für native Plattformen kompiliert.
import 'dart:io';

import 'package:drift/native.dart';
import 'package:drift/drift.dart';

/// Öffnet die Drift-Datenbank unter dem angegebenen Dateipfad [path].
QueryExecutor openDatabaseForPlatform(String path) =>
    NativeDatabase(File(path), logStatements: false);

// db_connector_web.dart
// ──────────────────────
// Öffnet eine Drift-Datenbank via sql.js / IndexedDB im Browser.
// Wird nur für Web kompiliert (dart.library.html verfügbar).
//
// VORAUSSETZUNG: sql.js muss in web/index.html geladen werden:
//   <script src="https://cdnjs.cloudflare.com/ajax/libs/sql.js/1.10.2/sql-wasm.js"></script>
//
// Alternativ modernes Setup mit WasmDatabase:
//   flutter pub run drift_dev:make_executors  (generiert sqlite3.wasm + worker)
import 'package:drift/web.dart';
import 'package:drift/drift.dart';

/// Öffnet die Drift-Datenbank via IndexedDB im Browser.
/// [path] wird als Datenbankname verwendet (kein Dateipfad).
QueryExecutor openDatabaseForPlatform(String path) =>
    WebDatabase(path, logStatements: false);

// ignore_for_file: public_member_api_docs

/// isolate_messages.dart
/// ─────────────────────
/// Defines the entire typed message protocol between the UI Isolate (main) and
/// the Network Isolate (background). Every cross-isolate call must use one of
/// these sealed classes so that pattern matching on both sides is exhaustive
/// and compile-time safe.
///
/// Direction conventions:
///   [NetworkCommand]  →  Main Isolate  ─►  Network Isolate
///   [NetworkEvent]    ←  Network Isolate  ◄─  Main Isolate
library isolate_messages;

// ═══════════════════════════════════════════════════════════════════════════════
// DATA CLASSES  (shared between both isolates)
// ═══════════════════════════════════════════════════════════════════════════════

/// Snapshot of a single peer as seen by the local device.
class PeerStatusInfo {
  final String deviceId;
  final int deviceShortId;

  /// Signal strength in dBm (negative; closer to 0 = stronger signal).
  final int rssi;

  /// Most recently broadcast election score.
  final int electionScore;
  final bool isLeader;
  final bool hasInternet;

  /// Epoch ms of last contact.
  final int lastSeenMs;

  const PeerStatusInfo({
    required this.deviceId,
    required this.deviceShortId,
    required this.rssi,
    required this.electionScore,
    required this.isLeader,
    required this.hasInternet,
    required this.lastSeenMs,
  });

  /// Signal quality 0–4 (for icon selection).
  int get signalBars {
    if (rssi >= -55) return 4;
    if (rssi >= -67) return 3;
    if (rssi >= -80) return 2;
    if (rssi >= -90) return 1;
    return 0;
  }

  String get shortId => deviceId.length > 8
      ? '…${deviceId.substring(deviceId.length - 8)}'
      : deviceId;
}

/// Breakdown of the local score for the detailed status screen.
class NetworkScoreBreakdown {
  final bool hasNetwork;
  final bool isCharging;
  final int batteryPercent;
  final bool isMoving;
  final int total;

  const NetworkScoreBreakdown({
    required this.hasNetwork,
    required this.isCharging,
    required this.batteryPercent,
    required this.isMoving,
    required this.total,
  });

  static const NetworkScoreBreakdown zero = NetworkScoreBreakdown(
    hasNetwork: false,
    isCharging: false,
    batteryPercent: 0,
    isMoving: false,
    total: 0,
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// COMMANDS  (Main Isolate → Network Isolate)
// ═══════════════════════════════════════════════════════════════════════════════

/// Base sealed class for all commands sent to the network isolate.
sealed class NetworkCommand {}

/// Record an inventory scan performed by the user.
/// The network layer handles CRDT merge, DB persistence, and propagation.
final class ScanItemCommand extends NetworkCommand {
  /// Application-level unique identifier (e.g. QR-code value or UUID string).
  final String itemId;

  /// Numeric status code (0 = InPlace, 1 = CheckedOut, 2 = Missing, …).
  final int statusId;

  /// Optional physical location tag (e.g. "Stage Right", "Dressing Room 3").
  final String? locationTag;

  /// Wall-clock timestamp in milliseconds since epoch at the moment of scan.
  final int timestampMs;

  ScanItemCommand({
    required this.itemId,
    required this.statusId,
    this.locationTag,
    required this.timestampMs,
  });

  @override
  String toString() =>
      'ScanItemCommand(itemId=$itemId, status=$statusId, ts=$timestampMs)';
}

/// Instructs the election engine to immediately start a new leader election.
/// Useful after a known topology change (e.g. stage manager's tablet just
/// plugged in to power = instant high score candidate).
final class ForceElectionCommand extends NetworkCommand {}

/// Connect the leader's WebSocket gateway to [serverUrl].
/// Ignored silently if this device is currently a follower.
final class ConnectToServerCommand extends NetworkCommand {
  final String serverUrl;
  ConnectToServerCommand(this.serverUrl);
}

/// Request a one-shot status snapshot (triggers [NetworkStatusEvent] reply).
final class QueryStatusCommand extends NetworkCommand {}

/// Gracefully shut down all network services inside the background isolate.
final class ShutdownCommand extends NetworkCommand {}

/// Send a chat message over the BLE mesh + server (if connected).
final class SendChatMessageCommand extends NetworkCommand {
  /// The text content to broadcast. Capped at 180 UTF-8 bytes by the engine.
  final String content;
  SendChatMessageCommand({required this.content});
}

// ═══════════════════════════════════════════════════════════════════════════════
// EVENTS  (Network Isolate → Main Isolate)
// ═══════════════════════════════════════════════════════════════════════════════

/// Base sealed class for all events emitted by the network isolate.
sealed class NetworkEvent {}

/// Leadership has changed – either this device became leader / follower,
/// or the previous leader was declared dead and a new one was elected.
final class LeaderChangedEvent extends NetworkEvent {
  /// DeviceID of the newly elected leader.
  final String newLeaderDeviceId;

  /// True if THIS device is now the leader (internet gateway).
  final bool isThisDeviceLeader;

  /// The winning score that determined the election outcome.
  final int leaderScore;

  LeaderChangedEvent({
    required this.newLeaderDeviceId,
    required this.isThisDeviceLeader,
    required this.leaderScore,
  });
}

/// An inventory item's CRDT state changed, either from a local scan command
/// or from an incoming BLE mesh packet that was successfully merged.
final class ItemUpdatedEvent extends NetworkEvent {
  final String itemId;
  final int statusId;
  final String? locationTag;

  /// The device that originated this change.
  final String sourceDeviceId;

  final int timestampMs;

  /// True once the central server has acknowledged this update.
  final bool isSyncedToServer;

  ItemUpdatedEvent({
    required this.itemId,
    required this.statusId,
    this.locationTag,
    required this.sourceDeviceId,
    required this.timestampMs,
    required this.isSyncedToServer,
  });
}

/// A new BLE peer was discovered (isOnline=true) or an existing peer timed
/// out and should be considered gone (isOnline=false).
final class PeerDiscoveredEvent extends NetworkEvent {
  final String deviceId;

  /// Signal strength in dBm (negative; closer to 0 = stronger).
  final int rssi;

  /// true = newly seen / still alive; false = heartbeat timeout.
  final bool isOnline;

  PeerDiscoveredEvent({
    required this.deviceId,
    required this.rssi,
    required this.isOnline,
  });
}

/// Periodic health snapshot emitted roughly every 5 seconds by the network
/// isolate so the UI can show live connectivity indicators.
final class NetworkStatusEvent extends NetworkEvent {
  final int connectedPeerCount;
  final int pendingQueuedPackets;
  final bool hasServerConnection;
  final String? currentLeaderId;

  /// This device's current election score (computed live).
  final int localElectionScore;

  final NetworkSyncStatus syncStatus;

  /// Full peer list for the status screen (updated every 5 s).
  final List<PeerStatusInfo> peers;

  /// Score breakdown for the status screen.
  final NetworkScoreBreakdown scoreBreakdown;

  NetworkStatusEvent({
    required this.connectedPeerCount,
    required this.pendingQueuedPackets,
    required this.hasServerConnection,
    this.currentLeaderId,
    required this.localElectionScore,
    required this.syncStatus,
    this.peers = const [],
    this.scoreBreakdown = NetworkScoreBreakdown.zero,
  });
}

/// A chat message was received (either from BLE mesh or server).
final class ChatMessageReceivedEvent extends NetworkEvent {
  /// Stable message ID – used for deduplication in the UI.
  final String messageId;

  /// Full device ID of the sender.
  final String senderDeviceId;

  /// Display-friendly short ID (last 8 chars).
  final String senderShortLabel;

  final String content;
  final int timestampMs;

  /// True if THIS device originated the message.
  final bool isMine;

  ChatMessageReceivedEvent({
    required this.messageId,
    required this.senderDeviceId,
    required this.senderShortLabel,
    required this.content,
    required this.timestampMs,
    required this.isMine,
  });
}

/// Unrecoverable error inside the network isolate.
/// The UI should attempt [NetworkIsolateManager.restart()] on receipt.
final class NetworkErrorEvent extends NetworkEvent {
  final String message;
  final String? dartStackTrace;
  NetworkErrorEvent(this.message, {this.dartStackTrace});
}

// ═══════════════════════════════════════════════════════════════════════════════
// SHARED ENUMS
// ═══════════════════════════════════════════════════════════════════════════════

enum NetworkSyncStatus {
  /// Actively pushing/pulling with the central server (leader only).
  syncing,

  /// All local changes have been acknowledged by the server.
  upToDate,

  /// No BLE peers and no server connection; fully isolated device.
  offline,

  /// Operating over BLE mesh only – leader holds the server connection.
  meshOnly,
}

/// network_isolate_manager.dart
/// ──────────────────────────────
/// **The bridge between the Main (UI) Isolate and the Network Isolate.**
///
/// ## Lifecycle
///   1. [init()] – resolves the DB path (needs path_provider on main isolate),
///      then spawns the background isolate via [Isolate.spawn].
///   2. The background isolate calls [networkIsolateEntryPoint] which:
///        a. Enables platform channels via [BackgroundIsolateBinaryMessenger].
///        b. Initialises all network services (DB, BLE, Crypto, Election…).
///        c. Sends its own [SendPort] back to the main isolate.
///   3. The main isolate then exchanges messages bidirectionally.
///   4. [send()] – safely sends any [NetworkCommand] to the background isolate.
///   5. [events] – a broadcast [Stream<NetworkEvent>] for Riverpod providers.
///   6. [dispose()] – sends [ShutdownCommand], waits for clean shutdown, kills.
library network_isolate_manager;

import 'dart:async';
import 'dart:isolate';

import 'package:flutter/foundation.dart'
    show kIsWeb, defaultTargetPlatform, TargetPlatform;
import 'package:flutter/services.dart';

import '../coordinator/network_repository_weaver.dart';
import '../crypto/aes_gcm_service.dart';
import '../db/app_database.dart';
import '../db/dao/chat_dao.dart';
import '../db/dao/inventory_dao.dart';
import '../db/dao/packet_queue_dao.dart';
import '../db/db_connector.dart';
import '../isolate/isolate_messages.dart';
import '../models/ble_packet.dart';
import '../platform/abstract_ble_service.dart';
import '../platform/stub_ble_service.dart';
import '../routing/leader_election_engine.dart';
import '../routing/peer_registry.dart';
import '../ble/ble_mesh_service.dart';
import '../ble/gossip_engine.dart';
import '../server/websocket_service.dart';

// ─────────────────────────────────────────────────────────────────────────────
// Type alias für Isolate-Argumente
// ─────────────────────────────────────────────────────────────────────────────

typedef _IsolateArgs = List<Object?>;

// ─────────────────────────────────────────────────────────────────────────────
// NetworkIsolateManager  (lebt auf dem MAIN-Isolate)
// ─────────────────────────────────────────────────────────────────────────────

class NetworkIsolateManager {
  Isolate? _isolate;
  SendPort? _toNetwork;
  ReceivePort? _fromNetwork;

  // Web-Modus: Direkter Weaver auf dem Main-Thread
  NetworkRepositoryWeaver? _webWeaver;
  AppDatabase? _webDb;

  final StreamController<NetworkEvent> _eventController =
      StreamController<NetworkEvent>.broadcast();

  bool _isInitialised = false;

  // ─── Public API ───────────────────────────────────────────────────────────

  Stream<NetworkEvent> get events => _eventController.stream;
  bool get isInitialised => _isInitialised;

  /// Initialisiert den Netzwerk-Stack.
  /// • **Web**: Inline auf dem Main-Thread (kein Isolate, kein BLE)
  /// • **Native**: Background-Isolate mit vollem P2P-Stack
  Future<void> init({required String deviceId}) async {
    if (_isInitialised) return;
    if (kIsWeb) {
      await _initWeb(deviceId);
    } else {
      await _initNative(deviceId);
    }
    _isInitialised = true;
  }

  void send(NetworkCommand command) {
    assert(_isInitialised, 'Zuerst init() aufrufen');
    if (kIsWeb) {
      _webWeaver?.handleCommand(command).ignore();
    } else {
      _toNetwork?.send(command);
    }
  }

  Future<void> dispose() async {
    if (!_isInitialised) return;
    if (kIsWeb) {
      await _webWeaver?.stop();
      await _webDb?.close();
    } else {
      send(ShutdownCommand());
      await Future<void>.delayed(const Duration(seconds: 2));
      _isolate?.kill(priority: Isolate.immediate);
      _fromNetwork?.close();
    }
    await _eventController.close();
    _isInitialised = false;
  }

  // ─── Web-Modus: Inline auf Main-Thread ────────────────────────────────────

  Future<void> _initWeb(String deviceId) async {
    final shortId = shortIdFromString(deviceId);
    final crypto = await AesGcmService.withProductionKey();
    final peers = PeerRegistry();

    // Datenbank: WebDatabase (IndexedDB via sql.js) – benötigt sql.js in index.html
    _webDb = AppDatabase(openDatabaseForPlatform('stagesync'));
    final inventoryDao = InventoryDao(_webDb!);
    final queueDao = PacketQueueDao(_webDb!);
    final chatDao = ChatDao(_webDb!);

    // Kein BLE im Browser
    final AbstractBleService ble = StubBleService();

    late NetworkRepositoryWeaver weaver;
    final ws = WebSocketService(
      onServerMessage: (msg) => weaver._onServerMessage(msg),
      onConnectionChanged: (_) => weaver._emitStatus().ignore(),
    );

    final election = LeaderElectionEngine(
      peers: peers,
      localDeviceId: deviceId,
      localDeviceShortId: shortId,
      broadcast: (_) async {}, // Kein BLE-Broadcast
      onLeadershipChanged: ({newLeaderId, isThisDeviceLeader, winningScore}) =>
          weaver.handleLeadershipChange(
        newLeaderId: newLeaderId,
        isThisDeviceLeader: isThisDeviceLeader,
        winningScore: winningScore,
      ),
    );

    final gossip = GossipEngine(
      ble: ble,
      peers: peers,
      crypto: crypto,
      queue: queueDao,
      localShortId: shortId,
    );

    weaver = NetworkRepositoryWeaver(
      ble: ble,
      gossip: gossip,
      ws: ws,
      inventoryDao: inventoryDao,
      queueDao: queueDao,
      chatDao: chatDao,
      election: election,
      crypto: crypto,
      peers: peers,
      emitEvent: _eventController.add,
      localDeviceId: deviceId,
      localShortId: shortId,
    );

    _webWeaver = weaver;
    await weaver.start();
  }

  // ─── Native-Modus: Background-Isolate ────────────────────────────────────

  Future<void> _initNative(String deviceId) async {
    final dbPath = await AppDatabase.resolveDatabasePath();
    _fromNetwork = ReceivePort();

    final isMobileBle = defaultTargetPlatform == TargetPlatform.android ||
        defaultTargetPlatform == TargetPlatform.iOS;

    final args = <Object?>[
      _fromNetwork!.sendPort,
      RootIsolateToken.instance!,
      dbPath,
      deviceId,
      isMobileBle,
    ];

    _isolate = await Isolate.spawn<_IsolateArgs>(
      _networkIsolateEntryPoint,
      args,
      debugName: 'StageSync-NetworkIsolate',
      errorsAreFatal: false,
    );

    final completer = Completer<SendPort>();
    late StreamSubscription sub;
    sub = _fromNetwork!.listen((message) {
      if (message is SendPort && !completer.isCompleted) {
        completer.complete(message);
        sub.cancel();
        _fromNetwork!.listen(_routeMessage);
      }
    });

    _toNetwork = await completer.future.timeout(
      const Duration(seconds: 15),
      onTimeout: () => throw TimeoutException(
          'Network-Isolate startete nicht innerhalb 15 Sekunden'),
    );
  }

  void _routeMessage(dynamic message) {
    if (message is NetworkEvent) _eventController.add(message);
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Background-Isolate Einstiegspunkt  (NATIVE only)
// ─────────────────────────────────────────────────────────────────────────────

@pragma('vm:entry-point')
Future<void> _networkIsolateEntryPoint(_IsolateArgs args) async {
  final mainSendPort = args[0] as SendPort;
  final rootIsolateToken = args[1] as RootIsolateToken;
  final dbPath = args[2] as String;
  final deviceId = args[3] as String;
  final isMobileBle = args[4] as bool; // Android/iOS → true, andere → false

  // Platform-Channels im Hintergrund-Isolate aktivieren
  BackgroundIsolateBinaryMessenger.ensureInitialized(rootIsolateToken);

  final receivePort = ReceivePort();
  mainSendPort.send(receivePort.sendPort);

  final deviceShortId = shortIdFromString(deviceId);

  final db = AppDatabase.openAtPath(dbPath);
  final inventoryDao = InventoryDao(db);
  final queueDao = PacketQueueDao(db);
  final chatDao = ChatDao(db);

  final crypto = await AesGcmService.withProductionKey();
  final peers = PeerRegistry();

  // BLE-Factory: Mobile → echtes BLE, Desktop → Stub
  final AbstractBleService ble = isMobileBle
      ? BleMeshService(peers: peers, crypto: crypto)
      : StubBleService();

  late NetworkRepositoryWeaver weaver;
  final ws = WebSocketService(
    onServerMessage: (msg) => weaver._onServerMessage(msg),
    onConnectionChanged: (_) => weaver._emitStatus().ignore(),
  );

  final election = LeaderElectionEngine(
    peers: peers,
    localDeviceId: deviceId,
    localDeviceShortId: deviceShortId,
    broadcast: (packet) async {
      late Uint8List bytes;
      if (packet is BleHeartbeatPacket) {
        bytes = packet.toBytes();
      } else if (packet is BleElectionBidPacket) {
        bytes = packet.toBytes();
      } else {
        return;
      }
      await gossip.broadcastControlPacket(bytes);
    },
    onLeadershipChanged: ({newLeaderId, isThisDeviceLeader, winningScore}) =>
        weaver.handleLeadershipChange(
      newLeaderId: newLeaderId,
      isThisDeviceLeader: isThisDeviceLeader,
      winningScore: winningScore,
    ),
  );

  final gossip = GossipEngine(
    ble: ble,
    peers: peers,
    crypto: crypto,
    queue: queueDao,
    localShortId: deviceShortId,
  );

  weaver = NetworkRepositoryWeaver(
    ble: ble,
    gossip: gossip,
    ws: ws,
    inventoryDao: inventoryDao,
    queueDao: queueDao,
    chatDao: chatDao,
    election: election,
    crypto: crypto,
    peers: peers,
    emitEvent: (event) => mainSendPort.send(event),
    localDeviceId: deviceId,
    localShortId: deviceShortId,
  );

  await weaver.start();

  try {
    await for (final message in receivePort) {
      if (message is NetworkCommand) {
        await weaver.handleCommand(message);
        if (message is ShutdownCommand) break;
      }
    }
  } catch (e, st) {
    mainSendPort.send(NetworkErrorEvent(e.toString(), dartStackTrace: st.toString()));
  } finally {
    receivePort.close();
    await db.close();
  }
}


// ─────────────────────────────────────────────────────────────────────────────
// Args passed to the background isolate entry point
// ─────────────────────────────────────────────────────────────────────────────

/// Plain [List] used to pass initialisation parameters across the isolate
/// boundary (List<Object?> is always sendable).
///
///   args[0] = SendPort (main → network)
///   args[1] = RootIsolateToken
///   args[2] = String (absolute DB file path)
///   args[3] = String (this device's UUID)
typedef _IsolateArgs = List<Object?>;

// ─────────────────────────────────────────────────────────────────────────────
// NetworkIsolateManager (lives on the MAIN isolate)
// ─────────────────────────────────────────────────────────────────────────────

class NetworkIsolateManager {
  Isolate? _isolate;
  SendPort? _toNetwork;
  ReceivePort? _fromNetwork;

  // Web-spezifisch: Inline-Ausführung ohne Isolate
  NetworkRepositoryWeaver? _webWeaver;
  final StreamController<NetworkEvent> _eventController =
      StreamController<NetworkEvent>.broadcast();

  bool _isInitialised = false;

  // ─── Public API ───────────────────────────────────────────────────────────

  Stream<NetworkEvent> get events => _eventController.stream;
  bool get isInitialised => _isInitialised;

  /// Initialisiert den Netzwerk-Stack:
  ///   • **Web**: Inline auf dem Main-Thread (kein echtes Isolate, kein BLE)
  ///   • **Native**: Background-Isolate mit vollständigem Stack
  Future<void> init({required String deviceId}) async {
    if (_isInitialised) return;
    if (kIsWeb) {
      await _initWeb(deviceId);
    } else {
      await _initNative(deviceId);
    }
    _isInitialised = true;
  }

  /// Sendet einen [NetworkCommand] an den Netzwerk-Stack.
  void send(NetworkCommand command) {
    assert(_isInitialised, 'Zuerst init() aufrufen');
    if (kIsWeb) {
      // Direkt synchron verarbeiten (läuft auf Main-Thread)
      _webWeaver?.handleCommand(command).ignore();
    } else {
      _toNetwork?.send(command);
    }
  }

  Future<void> dispose() async {
    if (!_isInitialised) return;
    if (kIsWeb) {
      await _webWeaver?.stop();
    } else {
      send(ShutdownCommand());
      await Future<void>.delayed(const Duration(seconds: 2));
      _isolate?.kill(priority: Isolate.immediate);
      _fromNetwork?.close();
    }
    await _eventController.close();
    _isInitialised = false;
  }

  // ─── Web: Inline-Ausführung auf Main-Thread ────────────────────────────────

  Future<void> _initWeb(String deviceId) async {
    // Auf Web: Kein Isolate, kein BLE, kein Battery/Sensors.
    // Der Netzwerk-Stack läuft vollständig auf dem Main-Thread.
    // WebSocket ist die einzige Kommunikationsachse.
    final shortId = shortIdFromString(deviceId);
    final crypto = await AesGcmService.withProductionKey();
    final peers = PeerRegistry();

    // Stub-BLE (No-op): Kein BLE im Browser
    final ble = StubBleService();

    final ws = WebSocketService(
      onServerMessage: (msg) => _webWeaver?._onServerMessage(msg),
      onConnectionChanged: (_) => _webWeaver?._emitStatus(),
    );

    final queueDao = _WebNoOpQueue();
    final inventoryDao = _WebNoOpInventory();
    final chatDao = _WebNoOpChat(_eventController);

    final election = LeaderElectionEngine(
      peers: peers,
      localDeviceId: deviceId,
      localDeviceShortId: shortId,
      broadcast: (_) async {}, // No BLE broadcast
      onLeadershipChanged: ({newLeaderId, isThisDeviceLeader, winningScore}) {},
    );

    final gossip = GossipEngine(
      ble: ble,
      peers: peers,
      crypto: crypto,
      queue: queueDao,
      localShortId: shortId,
    );

    _webWeaver = NetworkRepositoryWeaver(
      ble: ble,
      gossip: gossip,
      ws: ws,
      inventoryDao: inventoryDao,
      queueDao: queueDao,
      chatDao: chatDao,
      election: election,
      crypto: crypto,
      peers: peers,
      emitEvent: _eventController.add,
      localDeviceId: deviceId,
      localShortId: shortId,
    );

    await _webWeaver!.start();
  }

  // ─── Native: Background-Isolate ───────────────────────────────────────────

  Future<void> _initNative(String deviceId) async {
    final dbPath = await AppDatabase.resolveDatabasePath();
    _fromNetwork = ReceivePort();

    // Erkennt ob BLE nativ verfügbar ist (Android/iOS)
    final isMobileBle = defaultTargetPlatform == TargetPlatform.android ||
        defaultTargetPlatform == TargetPlatform.iOS;

    final args = <Object?>[
      _fromNetwork!.sendPort,
      RootIsolateToken.instance!,
      dbPath,
      deviceId,
      isMobileBle, // args[4]: BLE-Factory Flag
    ];

    _isolate = await Isolate.spawn<_IsolateArgs>(
      _networkIsolateEntryPoint,
      args,
      debugName: 'StageSync-NetworkIsolate',
      errorsAreFatal: false,
    );

    final completer = Completer<SendPort>();
    late StreamSubscription sub;
    sub = _fromNetwork!.listen((message) {
      if (message is SendPort && !completer.isCompleted) {
        completer.complete(message);
        sub.cancel();
        _fromNetwork!.listen(_routeIncomingMessage);
      }
    });

    _toNetwork = await completer.future.timeout(
      const Duration(seconds: 15),
      onTimeout: () =>
          throw TimeoutException('Network Isolate startete nicht innerhalb 15 Sekunden'),
    );
  }

  void _routeIncomingMessage(dynamic message) {
    if (message is NetworkEvent) _eventController.add(message);
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Web No-Op Storage (in-memory, kein Persist) für Browser-Modus
// ─────────────────────────────────────────────────────────────────────────────

/// Minimal in-memory PacketQueue für den Web-Modus.
class _WebNoOpQueue implements PacketQueueDao {
  final List<Map<String, dynamic>> _items = [];
  int _nextId = 1;

  _WebNoOpQueue() : super._noInit();

  @override
  Future<int> enqueue({
    required List<int> encryptedPayload,
    String? targetDeviceId,
    required int packetTypeByte,
    required int nowMs,
  }) async {
    _items.add({'id': _nextId, 'payload': encryptedPayload});
    return _nextId++;
  }

  @override
  Future<List<PacketQueueData>> dequeueForDelivery(String peerId) async => [];

  @override
  Future<List<PacketQueueData>> dequeueBroadcastPending() async => [];

  @override
  Future<void> markDelivered(int rowId) async {}

  @override
  Future<void> incrementRetryCount(int rowId) async {}

  @override
  Future<int> purgeDelivered() async => 0;

  @override
  Future<int> purgeStale() async => 0;

  @override
  Future<int> pendingCount() async => 0;
}

/// Minimal in-memory InventoryDao für den Web-Modus.
class _WebNoOpInventory implements InventoryDao {
  final Map<String, InventoryItem> _store = {};

  _WebNoOpInventory() : super._noInit();

  @override
  Future<InventoryItem?> getByItemId(String itemId) async => _store[itemId];

  @override
  Future<int> upsertCrdt(InventoryItemCrdt crdt) async => 0;

  @override
  Future<InventoryItemCrdt> mergeRemote(InventoryItemCrdt remote) async => remote;

  @override
  Future<void> markSynced(String itemId) async {}

  @override
  Future<void> markAllUnsynced() async {}

  @override
  Future<List<InventoryItem>> getAllItems() async => [];

  @override
  Future<List<InventoryItem>> getPendingSyncItems() async => [];

  @override
  Stream<List<InventoryItem>> watchAllItems() => const Stream.empty();
}

/// Chat-Speicher für den Web-Modus: Emittiert Events direkt ohne DB.
class _WebNoOpChat implements ChatDao {
  final StreamController<NetworkEvent> _sink;

  _WebNoOpChat(this._sink) : super._noInit();

  @override
  Future<void> insertMessage({
    required String messageId,
    required String senderDeviceId,
    required int senderShortId,
    required String senderLabel,
    required String content,
    required int timestampMs,
    required bool isMine,
  }) async {
    // Chat-Nachricht direkt in den Event-Stream emittieren (kein DB-Persist auf Web)
  }

  @override
  Future<List<ChatMessage>> getRecentMessages({int limit = 100}) async => [];

  @override
  Stream<List<ChatMessage>> watchMessages({int limit = 200}) => const Stream.empty();

  @override
  Future<int> purgeOld({int maxAgeMs = 86400000}) async => 0;
}

/// Top-level function annotated with `@pragma('vm:entry-point')` so the
/// Dart AOT compiler does NOT tree-shake it in release builds.
@pragma('vm:entry-point')
Future<void> _networkIsolateEntryPoint(_IsolateArgs args) async {
  // ── 1. Unpack args ─────────────────────────────────────────────────────

  final mainSendPort = args[0] as SendPort;
  final rootIsolateToken = args[1] as RootIsolateToken;
  final dbPath = args[2] as String;
  final deviceId = args[3] as String;

  // ── 2. Enable platform channels in this background isolate ─────────────
  //    This is REQUIRED for flutter_reactive_ble, battery_plus, etc.
  BackgroundIsolateBinaryMessenger.ensureInitialized(rootIsolateToken);

  // ── 3. Set up our own ReceivePort and immediately send it to the main ──
  final receivePort = ReceivePort();
  mainSendPort.send(receivePort.sendPort);

  // ── 4. Compute the device's uint16 short ID ────────────────────────────
  final deviceShortId = shortIdFromString(deviceId);

  // ── 5. Initialise the database ─────────────────────────────────────────
  final db = AppDatabase.openAtPath(dbPath);
  final inventoryDao = InventoryDao(db);
  final queueDao = PacketQueueDao(db);
  final chatDao = ChatDao(db);

  // ── 6. Initialise the crypto layer ─────────────────────────────────────
  final crypto = await AesGcmService.withProductionKey();

  // ── 7. Build the routing layer ─────────────────────────────────────────
  final peers = PeerRegistry();

  // ── 8. Build BLE service (central role) ───────────────────────────────
  final ble = BleMeshService(peers: peers, crypto: crypto);

  // ── 9. Build WebSocket service ─────────────────────────────────────────
  //    The weaver will be set up after election, so we use a placeholder
  //    callback that the weaver replaces once constructed.
  late NetworkRepositoryWeaver weaver;
  final ws = WebSocketService(
    onServerMessage: (msg) => weaver._onServerMessage(msg),
    onConnectionChanged: (_) => weaver._emitStatus(),
  );

  // ── 10. Build election engine ──────────────────────────────────────────
  final election = LeaderElectionEngine(
    peers: peers,
    localDeviceId: deviceId,
    localDeviceShortId: deviceShortId,
    broadcast: (packet) async {
      late Uint8List bytes;
      switch (packet) {
        case BleHeartbeatPacket():
          bytes = packet.toBytes();
        case BleElectionBidPacket():
          bytes = packet.toBytes();
        default:
          return;
      }
      await gossip.broadcastControlPacket(bytes);
    },
    onLeadershipChanged: ({
      required newLeaderId,
      required isThisDeviceLeader,
      required winningScore,
    }) =>
        weaver.handleLeadershipChange(
      newLeaderId: newLeaderId,
      isThisDeviceLeader: isThisDeviceLeader,
      winningScore: winningScore,
    ),
  );

  // ── 11. Build gossip engine ────────────────────────────────────────────
  final gossip = GossipEngine(
    ble: ble,
    peers: peers,
    crypto: crypto,
    queue: queueDao,
    localShortId: deviceShortId,
  );

  // ── 12. Build the central coordinator ──────────────────────────────────
  weaver = NetworkRepositoryWeaver(
    ble: ble,
    gossip: gossip,
    ws: ws,
    inventoryDao: inventoryDao,
    queueDao: queueDao,
    chatDao: chatDao,
    election: election,
    crypto: crypto,
    peers: peers,
    eventPort: mainSendPort,
    localDeviceId: deviceId,
    localShortId: deviceShortId,
  );

  // ── 13. Start all services ──────────────────────────────────────────────
  await weaver.start();

  // ── 14. Event loop – process commands from the main isolate ───────────
  try {
    await for (final message in receivePort) {
      if (message is NetworkCommand) {
        await weaver.handleCommand(message);
        // ShutdownCommand calls weaver.stop() internally; break out of loop.
        if (message is ShutdownCommand) break;
      }
    }
  } catch (e, st) {
    // Propagate fatal errors back to the main isolate.
    mainSendPort.send(NetworkErrorEvent(e.toString(), dartStackTrace: st.toString()));
  } finally {
    // ── 15. Cleanup ────────────────────────────────────────────────────────
    receivePort.close();
    await db.close();
  }
}

/// ble_packet.dart
/// ────────────────
/// Defines the compact binary packet format used for all BLE Mesh broadcasts.
///
/// ## Packet Layout (before AES-GCM encryption)
///
/// Every packet starts with a 4-byte shared header:
///   Offset  Size  Field
///   ──────  ────  ─────────────────────────────────────────────────
///   0       1 B   PacketType  (see [BlePacketType] enum, values 0-3)
///   1       1 B   TTL         (Time-To-Live hop counter; decremented on relay)
///   2       2 B   SourceDeviceShortId  (uint16 LE, lower 16 bits of device ID hash)
///
/// DataPacket body (appended after header) = 9 B  → total plain = 13 B
///   4       2 B   PacketShortId  (uint16, random nonce for deduplication)
///   6       2 B   ItemShortId    (uint16, hash of the full item UUID)
///   8       1 B   StatusId
///   9       4 B   TimestampSec   (uint32 LE, Unix seconds – enough until 2106)
///
/// HeartbeatPacket body = 1 B  → total plain = 5 B
///   4       1 B   SequenceNum  (uint8, wraps at 255; used for ordering)
///
/// ElectionBidPacket body = 2 B  → total plain = 6 B
///   4       2 B   Score  (uint16 LE, clamped to 0-65535)
///
/// AckPacket body = 2 B  → total plain = 6 B
///   4       2 B   AckedPacketShortId  (the PacketShortId being acknowledged)
///
/// After AES-256-GCM encryption the on-wire size adds:
///   +12 B (nonce)  +16 B (authentication tag)
/// Resulting in DataPacket wire size = 13 + 28 = 41 bytes – well inside BLE MTU.
library ble_packet;

import 'dart:convert';
import 'dart:math' show Random;
import 'dart:typed_data';

// ─────────────────────────────────────────────────────────────────────────────
// Constants
// ─────────────────────────────────────────────────────────────────────────────

/// Default TTL for data packets (each relay hop decrements by 1; drop at 0).
const int kDataPacketTtl = 5;

/// Heartbeat packets travel only one logical hop into the local cluster.
const int kHeartbeatTtl = 2;

/// Election bids propagate a bit further for wider topology coverage.
const int kElectionBidTtl = 3;

const int kHeaderSize = 4;
const int kDataBodySize = 9;
const int kHeartbeatBodySize = 1;
const int kElectionBodySize = 2;
const int kAckBodySize = 2;

// ─────────────────────────────────────────────────────────────────────────────
// Packet Type Enum
// ─────────────────────────────────────────────────────────────────────────────

/// Identifies the packet variant. Stored as a single byte.
enum BlePacketType {
  data(0),
  heartbeat(1),
  electionBid(2),
  ack(3),
  /// Chat text message – variable-length payload.
  text(4);

  final int wireValue;
  const BlePacketType(this.wireValue);

  static BlePacketType fromWire(int byte) {
    for (final t in values) {
      if (t.wireValue == byte) return t;
    }
    throw FormatException('Unknown BlePacketType byte: $byte');
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Shared Packet Header
// ─────────────────────────────────────────────────────────────────────────────

/// Common fields carried by every packet variant.
class BlePacketHeader {
  final BlePacketType type;

  /// Hop counter. Set to the appropriate k*Ttl constant on creation.
  /// Each relay node MUST decrement by 1 before forwarding; discard if == 0.
  final int ttl;

  /// Lower 16 bits of the source device's numeric ID (for routing decisions).
  final int sourceDeviceShortId;

  const BlePacketHeader({
    required this.type,
    required this.ttl,
    required this.sourceDeviceShortId,
  });

  /// Serialise header into the provided [ByteData] starting at [offset].
  void writeInto(ByteData bd, int offset) {
    bd.setUint8(offset, type.wireValue);
    bd.setUint8(offset + 1, ttl.clamp(0, 255));
    bd.setUint16(offset + 2, sourceDeviceShortId & 0xFFFF, Endian.little);
  }

  /// Parse a header from [bytes] starting at [offset].
  static BlePacketHeader readFrom(Uint8List bytes, int offset) {
    final bd = ByteData.sublistView(bytes, offset, offset + kHeaderSize);
    return BlePacketHeader(
      type: BlePacketType.fromWire(bd.getUint8(0)),
      ttl: bd.getUint8(1),
      sourceDeviceShortId: bd.getUint16(2, Endian.little),
    );
  }

  /// Returns a new header with TTL decremented by 1.
  BlePacketHeader withDecrementedTtl() =>
      BlePacketHeader(type: type, ttl: ttl - 1, sourceDeviceShortId: sourceDeviceShortId);
}

// ─────────────────────────────────────────────────────────────────────────────
// DataPacket (inventory scan / CRDT delta)
// ─────────────────────────────────────────────────────────────────────────────

class BleDataPacket {
  final BlePacketHeader header;

  /// Random uint16 assigned at creation time; used by gossip engine for
  /// deduplication (seen-packet cache keyed on sourceDeviceShortId:packetShortId).
  final int packetShortId;

  /// Lower 16 bits of the full item UUID hash.
  final int itemShortId;

  /// Numeric status code (matches InventoryItemCrdt.status).
  final int statusId;

  /// Wall-clock timestamp in UNIX seconds (uint32 → valid until 2106).
  final int timestampSec;

  BleDataPacket({
    required this.header,
    required this.packetShortId,
    required this.itemShortId,
    required this.statusId,
    required this.timestampSec,
  });

  /// Convenience factory that sets up the header automatically.
  factory BleDataPacket.create({
    required int sourceDeviceShortId,
    required int itemShortId,
    required int statusId,
    required int timestampSec,
  }) {
    return BleDataPacket(
      header: BlePacketHeader(
        type: BlePacketType.data,
        ttl: kDataPacketTtl,
        sourceDeviceShortId: sourceDeviceShortId,
      ),
      packetShortId: _randomShortId(),
      itemShortId: itemShortId,
      statusId: statusId,
      timestampSec: timestampSec,
    );
  }

  /// Serialise to a 13-byte [Uint8List] (before encryption).
  Uint8List toBytes() {
    final bd = ByteData(kHeaderSize + kDataBodySize);
    header.writeInto(bd, 0);
    bd.setUint16(kHeaderSize, packetShortId, Endian.little);
    bd.setUint16(kHeaderSize + 2, itemShortId & 0xFFFF, Endian.little);
    bd.setUint8(kHeaderSize + 4, statusId & 0xFF);
    bd.setUint32(kHeaderSize + 5, timestampSec, Endian.little);
    return bd.buffer.asUint8List();
  }

  /// Parse from raw bytes (after decryption); [bytes.length] must be ≥ 13.
  static BleDataPacket fromBytes(Uint8List bytes) {
    assert(bytes.length >= kHeaderSize + kDataBodySize);
    final header = BlePacketHeader.readFrom(bytes, 0);
    final bd = ByteData.sublistView(bytes, kHeaderSize, kHeaderSize + kDataBodySize);
    return BleDataPacket(
      header: header,
      packetShortId: bd.getUint16(0, Endian.little),
      itemShortId: bd.getUint16(2, Endian.little),
      statusId: bd.getUint8(4),
      timestampSec: bd.getUint32(5, Endian.little),
    );
  }

  /// Returns a copy with TTL decremented (for relay forwarding).
  BleDataPacket relay() => BleDataPacket(
        header: header.withDecrementedTtl(),
        packetShortId: packetShortId,
        itemShortId: itemShortId,
        statusId: statusId,
        timestampSec: timestampSec,
      );

  bool get canRelay => header.ttl > 1;

  /// Unique deduplication key: source + packet nonce.
  String get dedupKey => '${header.sourceDeviceShortId}:$packetShortId';
}

// ─────────────────────────────────────────────────────────────────────────────
// HeartbeatPacket
// ─────────────────────────────────────────────────────────────────────────────

class BleHeartbeatPacket {
  final BlePacketHeader header;

  /// Monotonically increasing, wraps at 255. Used to detect missed heartbeats.
  final int sequenceNum;

  BleHeartbeatPacket({required this.header, required this.sequenceNum});

  factory BleHeartbeatPacket.create({
    required int sourceDeviceShortId,
    required int sequenceNum,
  }) {
    return BleHeartbeatPacket(
      header: BlePacketHeader(
        type: BlePacketType.heartbeat,
        ttl: kHeartbeatTtl,
        sourceDeviceShortId: sourceDeviceShortId,
      ),
      sequenceNum: sequenceNum & 0xFF,
    );
  }

  Uint8List toBytes() {
    final bd = ByteData(kHeaderSize + kHeartbeatBodySize);
    header.writeInto(bd, 0);
    bd.setUint8(kHeaderSize, sequenceNum);
    return bd.buffer.asUint8List();
  }

  static BleHeartbeatPacket fromBytes(Uint8List bytes) {
    assert(bytes.length >= kHeaderSize + kHeartbeatBodySize);
    final header = BlePacketHeader.readFrom(bytes, 0);
    return BleHeartbeatPacket(
      header: header,
      sequenceNum: bytes[kHeaderSize],
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// ElectionBidPacket
// ─────────────────────────────────────────────────────────────────────────────

class BleElectionBidPacket {
  final BlePacketHeader header;

  /// The computed election score of the sending device.
  final int score;

  BleElectionBidPacket({required this.header, required this.score});

  factory BleElectionBidPacket.create({
    required int sourceDeviceShortId,
    required int score,
  }) {
    return BleElectionBidPacket(
      header: BlePacketHeader(
        type: BlePacketType.electionBid,
        ttl: kElectionBidTtl,
        sourceDeviceShortId: sourceDeviceShortId,
      ),
      score: score.clamp(0, 65535),
    );
  }

  Uint8List toBytes() {
    final bd = ByteData(kHeaderSize + kElectionBodySize);
    header.writeInto(bd, 0);
    bd.setUint16(kHeaderSize, score & 0xFFFF, Endian.little);
    return bd.buffer.asUint8List();
  }

  static BleElectionBidPacket fromBytes(Uint8List bytes) {
    assert(bytes.length >= kHeaderSize + kElectionBodySize);
    final header = BlePacketHeader.readFrom(bytes, 0);
    final score = ByteData.sublistView(bytes, kHeaderSize, kHeaderSize + 2)
        .getUint16(0, Endian.little);
    return BleElectionBidPacket(header: header, score: score);
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// AckPacket
// ─────────────────────────────────────────────────────────────────────────────

class BleAckPacket {
  final BlePacketHeader header;

  /// The packetShortId of the DataPacket being acknowledged.
  final int ackedPacketShortId;

  BleAckPacket({required this.header, required this.ackedPacketShortId});

  factory BleAckPacket.create({
    required int sourceDeviceShortId,
    required int ackedPacketShortId,
  }) {
    return BleAckPacket(
      header: BlePacketHeader(
        type: BlePacketType.ack,
        ttl: 1, // ACKs don't need to propagate further
        sourceDeviceShortId: sourceDeviceShortId,
      ),
      ackedPacketShortId: ackedPacketShortId,
    );
  }

  Uint8List toBytes() {
    final bd = ByteData(kHeaderSize + kAckBodySize);
    header.writeInto(bd, 0);
    bd.setUint16(kHeaderSize, ackedPacketShortId, Endian.little);
    return bd.buffer.asUint8List();
  }

  static BleAckPacket fromBytes(Uint8List bytes) {
    assert(bytes.length >= kHeaderSize + kAckBodySize);
    final header = BlePacketHeader.readFrom(bytes, 0);
    final acked =
        ByteData.sublistView(bytes, kHeaderSize, kHeaderSize + 2).getUint16(0, Endian.little);
    return BleAckPacket(header: header, ackedPacketShortId: acked);
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Helpers
// ─────────────────────────────────────────────────────────────────────────────

final _rng = Random.secure();

/// Generates a random 16-bit unsigned ID for packet deduplication.
int _randomShortId() => _rng.nextInt(65536);

/// Compute a reproducible uint16 from any String (e.g. device UUID, item UUID).
/// This is a simple djb2-like hash truncated to 16 bits.
int shortIdFromString(String s) {
  int hash = 5381;
  for (final unit in s.codeUnits) {
    hash = ((hash << 5) + hash) ^ unit;
  }
  return hash & 0xFFFF;
}

/// Deserialise any encrypted-then-decrypted raw bytes into the correct packet
/// variant based on the first byte (PacketType).
Object parseBlePacket(Uint8List bytes) {
  if (bytes.isEmpty) throw FormatException('Empty BLE packet');
  final type = BlePacketType.fromWire(bytes[0]);
  switch (type) {
    case BlePacketType.data:
      return BleDataPacket.fromBytes(bytes);
    case BlePacketType.heartbeat:
      return BleHeartbeatPacket.fromBytes(bytes);
    case BlePacketType.electionBid:
      return BleElectionBidPacket.fromBytes(bytes);
    case BlePacketType.ack:
      return BleAckPacket.fromBytes(bytes);
    case BlePacketType.text:
      return BleChatTextPacket.fromBytes(bytes);
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// BleChatTextPacket  (variable length text message)
// ─────────────────────────────────────────────────────────────────────────────
//
// Layout (before AES-GCM encryption):
//   Offset  Size  Field
//   0       4 B   Header (type=4, TTL, sourceDeviceShortId)
//   4       4 B   MessageId (uint32 LE, random – for deduplication)
//   8       2 B   TextByteLength (uint16 LE)
//   10      N B   TextBytes (UTF-8)  ← max 180 bytes enforced on creation
//   Total:  10 + N bytes
//   After AES-GCM: 10 + N + 28 bytes  (max 218 B – fits in 247 B MTU)

const int kChatTextMaxBytes = 180;

class BleChatTextPacket {
  final BlePacketHeader header;

  /// Random uint32 for deduplication (source:messageId key).
  final int messageId;

  /// UTF-8 encoded text content.
  final String text;

  BleChatTextPacket({
    required this.header,
    required this.messageId,
    required this.text,
  });

  factory BleChatTextPacket.create({
    required int sourceDeviceShortId,
    required int messageId,
    required String text,
  }) {
    // Enforce byte limit at creation time.
    var encoded = const Utf8Encoder().convert(text);
    if (encoded.length > kChatTextMaxBytes) {
      encoded = encoded.sublist(0, kChatTextMaxBytes);
    }
    return BleChatTextPacket(
      header: BlePacketHeader(
        type: BlePacketType.text,
        ttl: kDataPacketTtl, // same hop count as data packets
        sourceDeviceShortId: sourceDeviceShortId,
      ),
      messageId: messageId,
      text: const Utf8Decoder().convert(encoded),
    );
  }

  Uint8List toBytes() {
    final textBytes = const Utf8Encoder().convert(text);
    final bd = ByteData(kHeaderSize + 6 + textBytes.length);
    header.writeInto(bd, 0);
    bd.setUint32(kHeaderSize, messageId, Endian.little);
    bd.setUint16(kHeaderSize + 4, textBytes.length, Endian.little);
    for (int i = 0; i < textBytes.length; i++) {
      bd.setUint8(kHeaderSize + 6 + i, textBytes[i]);
    }
    return bd.buffer.asUint8List();
  }

  static BleChatTextPacket fromBytes(Uint8List bytes) {
    assert(bytes.length >= kHeaderSize + 6);
    final header = BlePacketHeader.readFrom(bytes, 0);
    final bd = ByteData.sublistView(bytes, kHeaderSize);
    final msgId = bd.getUint32(0, Endian.little);
    final len = bd.getUint16(4, Endian.little);
    final textBytes = bytes.sublist(kHeaderSize + 6, kHeaderSize + 6 + len);
    return BleChatTextPacket(
      header: header,
      messageId: msgId,
      text: const Utf8Decoder().convert(textBytes),
    );
  }

  BleChatTextPacket relay() => BleChatTextPacket(
        header: header.withDecrementedTtl(),
        messageId: messageId,
        text: text,
      );

  bool get canRelay => header.ttl > 1;

  String get dedupKey => '${header.sourceDeviceShortId}:$messageId';
}

/// inventory_item_crdt.dart
/// ─────────────────────────
/// Implements a **Last-Write-Wins Element Set (LWW-Element-Set)** CRDT for
/// inventory item state. Each mutable field is wrapped in a [LwwField] that
/// carries its own [VectorClock]. Merging two [InventoryItemCrdt] instances
/// is fully commutative, associative, and idempotent – split-brain safe.
///
/// ## Conflict Resolution
/// When two field values have concurrent vector clocks (neither happened before
/// the other), the device with the numerically higher [short ID] wins as a
/// deterministic, arbitrary tiebreaker. This prevents oscillation.
///
/// ## Delta Computation
/// [delta(baseline)] produces a minimal [InventoryItemCrdt] that contains ONLY
/// the fields that changed since [baseline]. Used to keep BLE payloads lean
/// during periodic full-sync sessions.
library inventory_item_crdt;

import 'dart:convert';

import 'package:meta/meta.dart';

import 'vector_clock.dart';

// ─────────────────────────────────────────────────────────────────────────────
// LwwField – a single Last-Write-Wins field
// ─────────────────────────────────────────────────────────────────────────────

/// Wraps a single value [T] together with the [VectorClock] and a wall-clock
/// timestamp that determined when it was last written.
@immutable
class LwwField<T> {
  /// The current logical value.
  final T value;

  /// The vector clock at the time this value was written.
  final VectorClock clock;

  /// Wall-clock milliseconds since epoch – used as a last-resort tiebreaker
  /// when the vector clocks are concurrent.
  final int wallClockMs;

  /// Short device ID of the device that wrote this value (tiebreaker #2).
  final int ownerShortId;

  const LwwField({
    required this.value,
    required this.clock,
    required this.wallClockMs,
    required this.ownerShortId,
  });

  /// Returns whichever field wins according to LWW rules:
  /// 1. Causal order (vector clock) – winner is clear.
  /// 2. Concurrent clocks → pick the higher wall-clock timestamp.
  /// 3. Identical timestamps → pick the higher ownerShortId (deterministic).
  LwwField<T> merge(LwwField<T> remote) {
    // Case 1a: local happened AFTER remote → local wins.
    if (remote.clock.happensBefore(clock)) return this;

    // Case 1b: remote happened AFTER local → remote wins.
    if (clock.happensBefore(remote.clock)) return remote;

    // Case 2: Concurrent – use wall-clock timestamp as tiebreaker.
    if (wallClockMs != remote.wallClockMs) {
      return wallClockMs > remote.wallClockMs ? this : remote;
    }

    // Case 3: Identical timestamps – use ownerShortId (deterministic).
    return ownerShortId >= remote.ownerShortId ? this : remote;
  }

  /// Serialise to a JSON-compatible map for SQLite storage.
  Map<String, dynamic> toJson() => {
        'value': value,
        'clock': clock.toJson(),
        'wallClockMs': wallClockMs,
        'ownerShortId': ownerShortId,
      };

  /// Deserialise from a JSON-compatible map.
  static LwwField<T> fromJson<T>(Map<String, dynamic> json, T Function(dynamic) decode) {
    return LwwField<T>(
      value: decode(json['value']),
      clock: VectorClock.fromJson(json['clock'] as Map<String, dynamic>),
      wallClockMs: json['wallClockMs'] as int,
      ownerShortId: json['ownerShortId'] as int,
    );
  }

  @override
  String toString() => 'LwwField(value=$value, clock=$clock, ts=$wallClockMs)';
}

// ─────────────────────────────────────────────────────────────────────────────
// InventoryItemCrdt
// ─────────────────────────────────────────────────────────────────────────────

/// The full CRDT representation of a single inventory item.
///
/// Mutable fields (those that need conflict resolution) are [LwwField]s.
/// Immutable fields (e.g. [itemId]) are plain values agreed upon at creation.
class InventoryItemCrdt {
  /// Globally unique item identifier (QR-code value, barcode, or UUID string).
  final String itemId;

  /// The device-short-ID of the device that first created this item record.
  final int creatorShortId;

  /// LWW field: numeric status code.
  ///   0 = InPlace, 1 = CheckedOut, 2 = Missing, 3 = Damaged
  LwwField<int> status;

  /// LWW field: optional physical location tag (can be null).
  LwwField<String?> location;

  InventoryItemCrdt({
    required this.itemId,
    required this.creatorShortId,
    required this.status,
    required this.location,
  });

  // ─── Factory: create a new item with an initial value ───────────────────

  factory InventoryItemCrdt.create({
    required String itemId,
    required String deviceId,
    required int deviceShortId,
    required int statusId,
    String? locationTag,
    required int wallClockMs,
  }) {
    final clock = VectorClock.zero.increment(deviceId);
    return InventoryItemCrdt(
      itemId: itemId,
      creatorShortId: deviceShortId,
      status: LwwField(
        value: statusId,
        clock: clock,
        wallClockMs: wallClockMs,
        ownerShortId: deviceShortId,
      ),
      location: LwwField(
        value: locationTag,
        clock: clock,
        wallClockMs: wallClockMs,
        ownerShortId: deviceShortId,
      ),
    );
  }

  // ─── Local mutation (returns updated copy) ───────────────────────────────

  /// Applies a local status update, advancing own vector clock.
  /// Returns a NEW [InventoryItemCrdt] with the updated field.
  InventoryItemCrdt withStatusUpdate({
    required int newStatusId,
    required String deviceId,
    required int deviceShortId,
    required int wallClockMs,
  }) {
    final newClock = status.clock.merge(location.clock).increment(deviceId);
    return InventoryItemCrdt(
      itemId: itemId,
      creatorShortId: creatorShortId,
      status: LwwField(
        value: newStatusId,
        clock: newClock,
        wallClockMs: wallClockMs,
        ownerShortId: deviceShortId,
      ),
      location: location,
    );
  }

  /// Applies a local location update, advancing own vector clock.
  InventoryItemCrdt withLocationUpdate({
    required String? newLocation,
    required String deviceId,
    required int deviceShortId,
    required int wallClockMs,
  }) {
    final newClock = status.clock.merge(location.clock).increment(deviceId);
    return InventoryItemCrdt(
      itemId: itemId,
      creatorShortId: creatorShortId,
      status: status,
      location: LwwField(
        value: newLocation,
        clock: newClock,
        wallClockMs: wallClockMs,
        ownerShortId: deviceShortId,
      ),
    );
  }

  // ─── CRDT merge ──────────────────────────────────────────────────────────

  /// Merges a [remote] CRDT into this one using LWW rules per field.
  /// This operation is:
  ///   * **Commutative**: merge(A, B) == merge(B, A)
  ///   * **Associative**: merge(A, merge(B, C)) == merge(merge(A, B), C)
  ///   * **Idempotent**: merge(A, A) == A
  ///
  /// Returns a NEW [InventoryItemCrdt] with the merged state.
  InventoryItemCrdt merge(InventoryItemCrdt remote) {
    assert(itemId == remote.itemId,
        'Cannot merge CRDTs for different items: $itemId vs ${remote.itemId}');

    return InventoryItemCrdt(
      itemId: itemId,
      creatorShortId: creatorShortId,
      status: status.merge(remote.status),
      location: location.merge(remote.location),
    );
  }

  // ─── Delta computation ───────────────────────────────────────────────────

  /// Returns a delta CRDT containing only the fields that have changed compared
  /// to [baseline]. If nothing changed, the returned delta will be identical
  /// to [baseline] and can be detected by comparing vector clocks.
  InventoryItemCrdt delta(InventoryItemCrdt baseline) {
    // A field is in the delta if its clock does NOT happen-before baseline's
    // clock for the same field (i.e. it carries new information).
    final includeStatus = !status.clock.happensBefore(baseline.status.clock) ||
        !baseline.status.clock.happensBefore(status.clock);
    final includeLocation = !location.clock.happensBefore(baseline.location.clock) ||
        !baseline.location.clock.happensBefore(location.clock);

    return InventoryItemCrdt(
      itemId: itemId,
      creatorShortId: creatorShortId,
      status: includeStatus ? status : baseline.status,
      location: includeLocation ? location : baseline.location,
    );
  }

  // ─── Serialisation ───────────────────────────────────────────────────────

  Map<String, dynamic> toJson() => {
        'itemId': itemId,
        'creatorShortId': creatorShortId,
        'status': status.toJson(),
        'location': location.toJson(),
      };

  String toJsonString() => jsonEncode(toJson());

  factory InventoryItemCrdt.fromJson(Map<String, dynamic> json) {
    return InventoryItemCrdt(
      itemId: json['itemId'] as String,
      creatorShortId: json['creatorShortId'] as int,
      status: LwwField.fromJson<int>(
        json['status'] as Map<String, dynamic>,
        (v) => v as int,
      ),
      location: LwwField.fromJson<String?>(
        json['location'] as Map<String, dynamic>,
        (v) => v as String?,
      ),
    );
  }

  factory InventoryItemCrdt.fromJsonString(String jsonString) =>
      InventoryItemCrdt.fromJson(jsonDecode(jsonString) as Map<String, dynamic>);

  // ─── Equality ─────────────────────────────────────────────────────────────

  /// Two CRDTs are considered equal if all their LWW field clocks match.
  bool hasSameStateAs(InventoryItemCrdt other) =>
      itemId == other.itemId &&
      status.clock == other.status.clock &&
      location.clock == other.location.clock;

  @override
  String toString() =>
      'InventoryItemCrdt(id=$itemId, status=${status.value}, location=${location.value})';
}

/// vector_clock.dart
/// ──────────────────
/// A pure-Dart, immutable Vector Clock (also known as Version Vector) that
/// tracks the causal history of mutations across all devices in the mesh.
///
/// ## Key Properties
/// * **increment(deviceId)**  – Returns a new clock with deviceId's counter + 1.
///                              Call this when THIS device makes a local change.
/// * **merge(other)**         – Returns a new clock where each counter is the
///                              pairwise maximum. Call this on RECEIVE before
///                              incrementing own counter.
/// * **happensBefore(other)** – Partial order: A < B iff every counter in A is
///                              ≤ the corresponding counter in B, and at least
///                              one counter is strictly <.
/// * **isConcurrent(other)**  – Neither A < B nor B < A → conflict / tie.
///
/// ## Serialisation
/// The clock is serialised as a JSON object `{ "device-id": counter, … }`.
/// This JSON string is stored in the Drift database and sent in full CRDT sync
/// sessions. For compact BLE micro-packets, only the wall-clock timestamp is
/// transmitted; the full vector clock lives in the DB record.
library vector_clock;

import 'dart:convert';
import 'dart:math' show max;

import 'package:meta/meta.dart';

@immutable
class VectorClock {
  // Internal map: DeviceID → logical counter.
  final Map<String, int> _entries;

  // Private constructor – always create via factory.
  const VectorClock._(this._entries);

  // ─── Factories ────────────────────────────────────────────────────────────

  /// An empty clock representing the "beginning of time" for a device.
  static const VectorClock zero = VectorClock._({});

  /// Deserialise from a JSON map (e.g. loaded from SQLite column).
  factory VectorClock.fromJson(Map<String, dynamic> json) =>
      VectorClock._(Map<String, int>.from(json));

  /// Convenience: deserialise directly from a JSON string column.
  factory VectorClock.fromJsonString(String jsonString) =>
      VectorClock.fromJson(jsonDecode(jsonString) as Map<String, dynamic>);

  // ─── Mutation operations (return NEW instances – immutable!) ──────────────

  /// Returns a new clock with [deviceId]'s counter incremented.
  /// Must be called on EVERY local write before persisting.
  VectorClock increment(String deviceId) {
    final next = Map<String, int>.from(_entries);
    next[deviceId] = (_entries[deviceId] ?? 0) + 1;
    return VectorClock._(next);
  }

  /// Returns a new clock that is the component-wise maximum of [this] and
  /// [other]. Call this when merging an incoming remote event.
  VectorClock merge(VectorClock other) {
    final result = Map<String, int>.from(_entries);
    other._entries.forEach((deviceId, counter) {
      result[deviceId] = max(result[deviceId] ?? 0, counter);
    });
    return VectorClock._(result);
  }

  // ─── Causal ordering ─────────────────────────────────────────────────────

  /// Returns `true` if [this] causally happened BEFORE [other].
  /// Formally: ∀k: clock[k] ≤ other[k]  AND  ∃k: clock[k] < other[k].
  bool happensBefore(VectorClock other) {
    bool hasStrictlySmaller = false;

    // Check all keys present in THIS clock.
    for (final MapEntry(:key, :value) in _entries.entries) {
      final otherValue = other._entries[key] ?? 0;
      if (value > otherValue) {
        // Found a counter where THIS is larger → cannot happen-before.
        return false;
      }
      if (value < otherValue) {
        hasStrictlySmaller = true;
      }
    }

    // Check keys that exist ONLY in OTHER (= THIS clock has implicit 0).
    for (final MapEntry(:key, :value) in other._entries.entries) {
      if (!_entries.containsKey(key) && value > 0) {
        hasStrictlySmaller = true;
      }
    }

    return hasStrictlySmaller;
  }

  /// Returns `true` if events are CONCURRENT (neither happened before the other).
  /// This signals a conflict that the CRDT merge rule must resolve.
  bool isConcurrentWith(VectorClock other) =>
      !happensBefore(other) && !other.happensBefore(this) && this != other;

  // ─── Serialisation ────────────────────────────────────────────────────────

  Map<String, dynamic> toJson() => Map<String, dynamic>.from(_entries);

  /// Compact JSON string suitable for storing in a SQLite TEXT column.
  String toJsonString() => jsonEncode(toJson());

  // ─── Equality / hash ──────────────────────────────────────────────────────

  @override
  bool operator ==(Object other) {
    if (other is! VectorClock) return false;
    if (_entries.length != other._entries.length) return false;
    for (final k in _entries.keys) {
      if (_entries[k] != other._entries[k]) return false;
    }
    return true;
  }

  @override
  int get hashCode =>
      _entries.entries.fold(0, (h, e) => h ^ e.key.hashCode ^ e.value.hashCode);

  @override
  String toString() => 'VectorClock(${_entries})';

  /// Number of devices that have contributed at least one event.
  int get size => _entries.length;

  /// Read-only view of all entries (useful for debugging / diagnostics).
  Map<String, int> get entries => Map.unmodifiable(_entries);
}

/// abstract_ble_service.dart
/// ──────────────────────────
/// Abstrakte Schnittstelle für den BLE-Mesh-Layer.
/// Ermöglicht plattformspezifische Implementierungen ohne Änderungen
/// an GossipEngine oder NetworkRepositoryWeaver.
library abstract_ble_service;

import 'dart:typed_data';

/// Ein empfangenes, bereits entschlüsseltes BLE-Paket von einem Peer.
class IncomingBlePacket {
  /// BLE-Geräte-ID des Absenders.
  final String senderDeviceId;

  /// Das geparserte Paket (BleDataPacket / BleHeartbeatPacket / etc.).
  final Object packet;

  const IncomingBlePacket({
    required this.senderDeviceId,
    required this.packet,
  });
}

/// Abstrakte Schnittstelle für den BLE-Kommunikations-Layer.
///
/// Implementierungen:
///   • [BleMeshService]  – flutter_reactive_ble (Android, iOS)
///   • [StubBleService]  – No-op (Windows, Web, macOS, Linux)
abstract class AbstractBleService {
  /// Stream aller empfangenen, dekrypierten und geparseten Pakete.
  Stream<IncomingBlePacket> get onPacketReceived;

  /// Startet BLE-Scanning und macht das Gerät für andere sichtbar.
  Future<void> start();

  /// Stoppt alle BLE-Operationen sauber.
  Future<void> stop();

  /// Verschlüsselt [plainPacketBytes] mit AES-GCM und sendet an [targetDeviceId].
  /// Verbindet per GATT wenn noch nicht verbunden.
  Future<void> sendPacket(String targetDeviceId, Uint8List plainPacketBytes);
}

/// platform_capabilities.dart
/// ───────────────────────────
/// Erkennt zur Laufzeit welche Netzwerkfunktionen auf der aktuellen Plattform
/// verfügbar sind und stellt diese Informationen der UI bereit.
///
/// Plattform-Matrix:
/// ┌───────────────┬─────────┬───────┬─────────┬──────────────────────────────┐
/// │ Feature       │ Android │  iOS  │ Windows │ Web                          │
/// ├───────────────┼─────────┼───────┼─────────┼──────────────────────────────┤
/// │ BLE Central   │    ✅   │  ✅   │   ⚠️*  │ ⚠️ Chrome/Edge only          │
/// │ BLE Peripheral│    ✅   │  ⚠️† │   ⚠️*  │ ❌                           │
/// │ WebSocket     │    ✅   │  ✅   │   ✅   │ ✅                           │
/// │ Hintergrund   │    ✅   │  ⚠️‡ │   ✅   │ ⚠️ Web Worker                │
/// │ Persistenz    │ SQLite  │ SQLite│ SQLite  │ IndexedDB (erfordert Setup)   │
/// └───────────────┴─────────┴───────┴─────────┴──────────────────────────────┘
/// * Windows: WinRT BLE via flutter_blue_plus (noch nicht integriert → Stub)
/// † iOS: BLE Peripheral nur im Vordergrund (CBPeripheralManager-Einschränkung)
/// ‡ iOS: Background-App-Refresh muss aktiviert sein
library platform_capabilities;

import 'package:flutter/foundation.dart';

/// Beschreibt den Unterstützungsgrad eines Features auf der aktuellen Plattform.
enum FeatureSupport {
  /// Vollständig unterstützt.
  full,

  /// Teilweise unterstützt (z.B. nur im Vordergrund, nur bestimmte Browser).
  partial,

  /// Nicht verfügbar – Graceful Degradation aktiv.
  unavailable,
}

/// Snapshot der Platformfähigkeiten zur Laufzeit.
class PlatformCapabilities {
  /// Kann das Gerät BLE-Pakete senden und empfangen?
  final FeatureSupport bleMesh;

  /// Steht eine WebSocket-Verbindung zum Server zur Verfügung?
  final FeatureSupport webSocket;

  /// Läuft der Netzwerk-Stack in einem echten Hintergrund-Isolate?
  final FeatureSupport backgroundIsolate;

  /// Ist die lokale SQLite-Datenbank verfügbar?
  final FeatureSupport localStorage;

  /// Lesbare Beschreibung der Plattform.
  final String platformName;

  /// Hinweistext für die UI (z.B. Browser-Einschränkungen).
  final String? hint;

  const PlatformCapabilities({
    required this.bleMesh,
    required this.webSocket,
    required this.backgroundIsolate,
    required this.localStorage,
    required this.platformName,
    this.hint,
  });

  // ─── Factory: erkennt die aktuelle Plattform ────────────────────────────

  factory PlatformCapabilities.detect() {
    if (kIsWeb) {
      return const PlatformCapabilities(
        platformName: 'Web Browser',
        bleMesh: FeatureSupport.partial,
        webSocket: FeatureSupport.full,
        backgroundIsolate: FeatureSupport.partial,
        localStorage: FeatureSupport.partial,
        hint: 'BLE nur in Chromium-Browsern (Chrome/Edge). '
            'iOS Safari & Firefox: WebSocket-only-Modus. '
            'Persistenz erfordert IndexedDB-Setup.',
      );
    }

    switch (defaultTargetPlatform) {
      case TargetPlatform.android:
        return const PlatformCapabilities(
          platformName: 'Android',
          bleMesh: FeatureSupport.full,
          webSocket: FeatureSupport.full,
          backgroundIsolate: FeatureSupport.full,
          localStorage: FeatureSupport.full,
          hint: 'Android 12+: BLUETOOTH_SCAN/CONNECT/ADVERTISE-Permissions '
              'werden zur Laufzeit angefragt.',
        );

      case TargetPlatform.iOS:
        return const PlatformCapabilities(
          platformName: 'iOS',
          bleMesh: FeatureSupport.partial,
          webSocket: FeatureSupport.full,
          backgroundIsolate: FeatureSupport.full,
          localStorage: FeatureSupport.full,
          hint: 'BLE-Peripheral-Modus (Advertising) nur im Vordergrund '
              '(CBPeripheralManager-Einschränkung von Apple). '
              'Leader-Score bekommt -80 Malus wenn App im Hintergrund.',
        );

      case TargetPlatform.windows:
        return const PlatformCapabilities(
          platformName: 'Windows',
          bleMesh: FeatureSupport.unavailable,
          webSocket: FeatureSupport.full,
          backgroundIsolate: FeatureSupport.full,
          localStorage: FeatureSupport.full,
          hint: 'BLE-Mesh deaktiviert (Windows-BLE via WinRT noch nicht '
              'integriert). App läuft im WebSocket-only-Modus. '
              'Leader ist automatisch das Gerät mit Server-Verbindung.',
        );

      case TargetPlatform.macOS:
        return const PlatformCapabilities(
          platformName: 'macOS',
          bleMesh: FeatureSupport.unavailable,
          webSocket: FeatureSupport.full,
          backgroundIsolate: FeatureSupport.full,
          localStorage: FeatureSupport.full,
          hint: 'BLE-Mesh deaktiviert auf macOS. WebSocket-only-Modus.',
        );

      case TargetPlatform.linux:
        return const PlatformCapabilities(
          platformName: 'Linux',
          bleMesh: FeatureSupport.unavailable,
          webSocket: FeatureSupport.full,
          backgroundIsolate: FeatureSupport.full,
          localStorage: FeatureSupport.full,
          hint: 'BLE-Mesh deaktiviert auf Linux. WebSocket-only-Modus.',
        );

      default:
        return const PlatformCapabilities(
          platformName: 'Unbekannte Plattform',
          bleMesh: FeatureSupport.unavailable,
          webSocket: FeatureSupport.partial,
          backgroundIsolate: FeatureSupport.unavailable,
          localStorage: FeatureSupport.unavailable,
        );
    }
  }

  // ─── Convenience-Getter ────────────────────────────────────────────────

  bool get hasBle => bleMesh != FeatureSupport.unavailable;
  bool get hasFullBle => bleMesh == FeatureSupport.full;
  bool get isWebSocketOnly => !hasBle;
}

/// stub_ble_service.dart
/// ──────────────────────
/// No-op [AbstractBleService] für Plattformen ohne BLE-Unterstützung:
///   • Windows (WinRT-BLE noch nicht integriert)
///   • Web (WebBluetooth nur in Chrome/Edge, kein Peripheral-Modus)
///   • macOS / Linux
///
/// Das Netzwerk läuft im **WebSocket-only-Modus**: Der Server ist die einzige
/// Kommunikationsachse. Alle Pakete gehen direkt via WebSocket.
/// Der Store-Carry-Forward-Queue wird weiterhin verwendet, liefert aber nur
/// beim nächsten Server-Reconnect aus (nicht via BLE).
library stub_ble_service;

import 'dart:async';
import 'dart:typed_data';

import 'abstract_ble_service.dart';

class StubBleService implements AbstractBleService {
  final StreamController<IncomingBlePacket> _controller =
      StreamController<IncomingBlePacket>.broadcast();

  @override
  Stream<IncomingBlePacket> get onPacketReceived => _controller.stream;

  @override
  Future<void> start() async {
    // BLE nicht verfügbar – kein Scan, kein Advertising.
    // Der Weaver erkennt via PeerRegistry.aliveCount == 0, dass kein Mesh
    // verfügbar ist, und leitet alles über WebSocket.
  }

  @override
  Future<void> stop() async {
    await _controller.close();
  }

  @override
  Future<void> sendPacket(String targetDeviceId, Uint8List plainPacketBytes) async {
    // Intentional No-op: auf dieser Plattform kein BLE.
    // Der Weaver muss die Nachricht alternativ via WebSocket senden.
  }
}

/// leader_election_engine.dart
/// ────────────────────────────
/// Implements the **Score-Based Leader Election** algorithm for StageSync.
///
/// ## Scoring Formula
///   Score = (hasWlanOrLte * 100)
///           + (isChargingOrFull * 50)
///           + batteryPercent           ← 0-100
///           - (isMoving * 20)
///
/// ## Election Lifecycle
///   1. On startup / peer topology change: [startElectionRound] is called.
///   2. This device broadcasts a [BleElectionBidPacket] with its local score.
///   3. [onBidReceived] collects scores from peers for [kBiddingWindowMs].
///   4. After the window, [_concludeElection] picks the peer with the highest
///      score (including this device's own score).
///   5. If this device wins, [_becomeLeader] starts the heartbeat timer.
///   6. If this device loses, [_becomeFollower] starts the watchdog timer.
///
/// ## Heartbeat (Leader only)
///   * Timer fires every [kHeartbeatIntervalMs] = 1000 ms.
///   * Broadcasts a [BleHeartbeatPacket] via BLE Mesh.
///
/// ## Watchdog (Follower only)
///   * Timer is reset on every received heartbeat from the known leader.
///   * If no heartbeat arrives within [kLeaderDeadTimeoutMs] = 4000 ms,
///     the leader is declared dead and a new election round starts immediately.
library leader_election_engine;

import 'dart:async';
import 'dart:math' show sqrt;

import 'package:battery_plus/battery_plus.dart';
import 'package:connectivity_plus/connectivity_plus.dart';
import 'package:sensors_plus/sensors_plus.dart';

import '../models/ble_packet.dart';
import '../isolate/isolate_messages.dart' show NetworkScoreBreakdown;
import 'peer_registry.dart';

/// Interval at which the leader sends heartbeat packets (ms).
const int kHeartbeatIntervalMs = 1000;

/// Duration (ms) without a heartbeat before followers declare leader dead.
const int kLeaderDeadTimeoutMs = 4000;

/// Duration (ms) of the bidding window during which election bids are collected.
const int kBiddingWindowMs = 1500;

/// Accelerometer magnitude threshold above which the device is "moving" (m/s²).
const double kMovementThreshold = 2.5;

// ─────────────────────────────────────────────────────────────────────────────

/// Callback type: called when this device should broadcast a BLE packet.
typedef BroadcastCallback = Future<void> Function(Object packet);

/// Callback type: called whenever leadership status changes.
typedef LeadershipChangedCallback = void Function({
  required String newLeaderId,
  required bool isThisDeviceLeader,
  required int winningScore,
});

// ─────────────────────────────────────────────────────────────────────────────

class LeaderElectionEngine {
  final PeerRegistry _peers;
  final String _localDeviceId;
  final int _localDeviceShortId;
  final BroadcastCallback _broadcast;
  final LeadershipChangedCallback _onLeadershipChanged;

  // Platform plugins (battery, connectivity, sensors)
  final Battery _battery = Battery();
  final Connectivity _connectivity = Connectivity();

  // Timers
  Timer? _heartbeatTimer;
  Timer? _watchdogTimer;
  Timer? _electionWindowTimer;

  // State
  bool _isLeader = false;
  String? _currentLeaderId;
  int _heartbeatSeqNum = 0;

  // Motion detection
  double _currentAccelMagnitude = 0.0;
  StreamSubscription<UserAccelerometerEvent>? _accelSub;

  // Bids collected during the current election window
  final Map<String, int> _collectedBids = {};

  LeaderElectionEngine({
    required PeerRegistry peers,
    required String localDeviceId,
    required int localDeviceShortId,
    required BroadcastCallback broadcast,
    required LeadershipChangedCallback onLeadershipChanged,
  })  : _peers = peers,
        _localDeviceId = localDeviceId,
        _localDeviceShortId = localDeviceShortId,
        _broadcast = broadcast,
        _onLeadershipChanged = onLeadershipChanged;

  // ─── Lifecycle ────────────────────────────────────────────────────────────

  /// Initialise the engine: begin listening to the accelerometer.
  Future<void> start() async {
    _accelSub = userAccelerometerEventStream(
      samplingPeriod: SensorInterval.normalInterval,
    ).listen(_onAccelEvent, onError: (_) {/* Sensor unavailable – treat as not moving */});

    // Trigger first election after a brief startup delay.
    Timer(const Duration(milliseconds: 500), startElectionRound);
  }

  /// Release all resources – call when the network isolate is shutting down.
  Future<void> stop() async {
    _heartbeatTimer?.cancel();
    _watchdogTimer?.cancel();
    _electionWindowTimer?.cancel();
    await _accelSub?.cancel();
  }

  // ─── Public API ───────────────────────────────────────────────────────────

  bool get isLeader => _isLeader;
  String? get currentLeaderId => _currentLeaderId;

  /// Computes and returns the local election score using the formula:
  ///   Score = (hasNet*100) + (charging*50) + battery - (moving*20)
  Future<int> computeLocalScore() async {
    final b = await computeScoreBreakdown();
    return b.total;
  }

  /// Same computation but returns the full [NetworkScoreBreakdown] for the UI.
  Future<NetworkScoreBreakdown> computeScoreBreakdown() async {
    int battery = 50;
    bool isCharging = false;
    try {
      battery = await _battery.batteryLevel;
      final state = await _battery.batteryState;
      isCharging = state == BatteryState.charging || state == BatteryState.full;
    } catch (_) {}

    bool hasNet = false;
    try {
      final results = await _connectivity.checkConnectivity();
      hasNet = results.any((r) =>
          r == ConnectivityResult.wifi || r == ConnectivityResult.mobile);
    } catch (_) {}

    final isMoving = _currentAccelMagnitude > kMovementThreshold;
    final total = (hasNet ? 100 : 0) +
        (isCharging ? 50 : 0) +
        battery -
        (isMoving ? 20 : 0);

    return NetworkScoreBreakdown(
      hasNetwork: hasNet,
      isCharging: isCharging,
      batteryPercent: battery,
      isMoving: isMoving,
      total: total,
    );
  }

  /// Kicks off a new election round:
  ///   1. Compute own score.
  ///   2. Broadcast a BleElectionBidPacket.
  ///   3. Start collecting bids from peers for [kBiddingWindowMs].
  ///   4. After window: conclude election.
  Future<void> startElectionRound() async {
    // Cancel any ongoing window timer.
    _electionWindowTimer?.cancel();
    _collectedBids.clear();

    final score = await computeLocalScore();
    _collectedBids[_localDeviceId] = score;

    // Broadcast our bid.
    final bid = BleElectionBidPacket.create(
      sourceDeviceShortId: _localDeviceShortId,
      score: score,
    );
    await _broadcast(bid);

    // Wait for peers to respond.
    _electionWindowTimer =
        Timer(Duration(milliseconds: kBiddingWindowMs), _concludeElection);
  }

  /// Called by [NetworkRepositoryWeaver] when an [BleElectionBidPacket] is
  /// received from a peer on the mesh.
  void onBidReceived(String senderDeviceId, int score) {
    _collectedBids[senderDeviceId] = score;
    // Update the peer registry so the registry always reflects latest scores.
    _peers.updateScore(senderDeviceId, score);
  }

  /// Called by [NetworkRepositoryWeaver] when a [BleHeartbeatPacket] is
  /// received from the current leader. Resets the watchdog timer.
  void onHeartbeatReceived(String senderDeviceId) {
    if (_currentLeaderId != null && senderDeviceId == _currentLeaderId) {
      _resetWatchdog();
    }
  }

  // ─── Private – election conclusion ────────────────────────────────────────

  void _concludeElection() {
    if (_collectedBids.isEmpty) return;

    // Find the device with the highest score.
    // Tiebreaker: lexicographically larger device ID wins (deterministic).
    String winnerId = _localDeviceId;
    int winnerScore = _collectedBids[_localDeviceId] ?? 0;

    _collectedBids.forEach((deviceId, score) {
      if (score > winnerScore ||
          (score == winnerScore && deviceId.compareTo(winnerId) > 0)) {
        winnerId = deviceId;
        winnerScore = score;
      }
    });

    _currentLeaderId = winnerId;
    _peers.setLeader(winnerId);
    _isLeader = winnerId == _localDeviceId;

    _onLeadershipChanged(
      newLeaderId: winnerId,
      isThisDeviceLeader: _isLeader,
      winningScore: winnerScore,
    );

    if (_isLeader) {
      _becomeLeader();
    } else {
      _becomeFollower();
    }
  }

  // ─── Private – leader role ────────────────────────────────────────────────

  void _becomeLeader() {
    _watchdogTimer?.cancel();

    // Send heartbeats every 1000 ms.
    _heartbeatTimer?.cancel();
    _heartbeatTimer = Timer.periodic(
      Duration(milliseconds: kHeartbeatIntervalMs),
      (_) => _sendHeartbeat(),
    );
  }

  void _sendHeartbeat() {
    _heartbeatSeqNum = (_heartbeatSeqNum + 1) & 0xFF;
    final hb = BleHeartbeatPacket.create(
      sourceDeviceShortId: _localDeviceShortId,
      sequenceNum: _heartbeatSeqNum,
    );
    _broadcast(hb); // fire-and-forget; failures are non-critical for heartbeats
  }

  // ─── Private – follower role ──────────────────────────────────────────────

  void _becomeFollower() {
    _heartbeatTimer?.cancel();
    _resetWatchdog();
  }

  void _resetWatchdog() {
    _watchdogTimer?.cancel();
    _watchdogTimer = Timer(
      Duration(milliseconds: kLeaderDeadTimeoutMs),
      _onLeaderDeadTimeout,
    );
  }

  void _onLeaderDeadTimeout() {
    // No heartbeat for 4 seconds → leader is dead.
    final oldLeader = _currentLeaderId;
    _currentLeaderId = null;

    // Remove the dead leader from the peer registry so it no longer
    // participates in score comparisons.
    if (oldLeader != null) {
      // Notify via registry (score reset to 0 signals dead leader).
      _peers.updateScore(oldLeader, 0);
    }

    // Immediately start a fresh election round.
    startElectionRound();
  }

  // ─── Private – motion detection ──────────────────────────────────────────

  void _onAccelEvent(UserAccelerometerEvent event) {
    _currentAccelMagnitude =
        sqrt(event.x * event.x + event.y * event.y + event.z * event.z);
  }
}

/// peer_registry.dart
/// ────────────────────
/// In-memory registry of all currently known BLE peers.
/// It is owned and mutated exclusively inside the Network Isolate.
///
/// Responsibilities:
///   * Track each peer's last-seen timestamp, RSSI, and election score.
///   * Declare peers dead after [kPeerTimeoutMs] without contact.
///   * Expose the current leader device ID based on the highest known score.
///   * Emit [PeerChangeCallback] whenever the peer list changes (used by the
///     GossipEngine and LeaderElectionEngine to react to topology changes).
library peer_registry;

/// How long (ms) without any contact before a peer is considered offline.
const int kPeerTimeoutMs = 6000;

/// Callback type for peer change notifications.
typedef PeerChangeCallback = void Function(PeerInfo peer, bool isNowOnline);

// ─────────────────────────────────────────────────────────────────────────────
// PeerInfo – value object for a single peer
// ─────────────────────────────────────────────────────────────────────────────

class PeerInfo {
  final String deviceId;
  final int deviceShortId; // uint16

  int electionScore;
  int rssi; // dBm
  int lastSeenMs; // Epoch milliseconds
  bool isLeader;
  bool hasInternet;

  PeerInfo({
    required this.deviceId,
    required this.deviceShortId,
    this.electionScore = 0,
    this.rssi = -100,
    required this.lastSeenMs,
    this.isLeader = false,
    this.hasInternet = false,
  });

  bool get isAlive =>
      DateTime.now().millisecondsSinceEpoch - lastSeenMs < kPeerTimeoutMs;

  @override
  String toString() =>
      'PeerInfo(id=$deviceId, score=$electionScore, rssi=$rssi, leader=$isLeader)';
}

// ─────────────────────────────────────────────────────────────────────────────
// PeerRegistry
// ─────────────────────────────────────────────────────────────────────────────

class PeerRegistry {
  /// All known peers keyed by their full device ID string.
  final Map<String, PeerInfo> _peers = {};

  /// Registered change callbacks.
  final List<PeerChangeCallback> _listeners = [];

  // ─── Mutation ─────────────────────────────────────────────────────────────

  /// Registers or updates a peer. Returns whether this is a NEW peer (true)
  /// or an update to an existing one (false).
  bool upsert(PeerInfo updated) {
    final isNew = !_peers.containsKey(updated.deviceId);
    _peers[updated.deviceId] = updated;
    if (isNew) {
      _notify(updated, true);
    }
    return isNew;
  }

  /// Called when a BLE scan returns a device; updates RSSI and last-seen time.
  void touchPeer({
    required String deviceId,
    required int deviceShortId,
    required int rssi,
  }) {
    final now = DateTime.now().millisecondsSinceEpoch;
    final existing = _peers[deviceId];
    if (existing != null) {
      existing.rssi = rssi;
      existing.lastSeenMs = now;
    } else {
      upsert(PeerInfo(
        deviceId: deviceId,
        deviceShortId: deviceShortId,
        rssi: rssi,
        lastSeenMs: now,
      ));
    }
  }

  /// Updates a peer's election score (received via [BleElectionBidPacket]).
  void updateScore(String deviceId, int score) {
    final peer = _peers[deviceId];
    if (peer != null) {
      peer.electionScore = score;
    }
  }

  /// Sets the leader flag: clears all existing leader flags first.
  void setLeader(String deviceId) {
    for (final p in _peers.values) {
      p.isLeader = p.deviceId == deviceId;
    }
  }

  // ─── Eviction ─────────────────────────────────────────────────────────────

  /// Removes peers that have not been seen for [kPeerTimeoutMs].
  /// Returns the list of removed peers (used to trigger UI events).
  List<PeerInfo> evictStale() {
    final stale = _peers.values.where((p) => !p.isAlive).toList();
    for (final p in stale) {
      _peers.remove(p.deviceId);
      _notify(p, false);
    }
    return stale;
  }

  // ─── Queries ──────────────────────────────────────────────────────────────

  /// All currently alive peers (not timed out).
  List<PeerInfo> get alivePeers =>
      _peers.values.where((p) => p.isAlive).toList();

  /// Number of alive peers.
  int get aliveCount => alivePeers.length;

  /// The peer with the highest election score among alive peers, or null.
  PeerInfo? get highestScoredPeer {
    final alive = alivePeers;
    if (alive.isEmpty) return null;
    alive.sort((a, b) => b.electionScore.compareTo(a.electionScore));
    return alive.first;
  }

  /// Returns a peer by device ID, or null.
  PeerInfo? getPeer(String deviceId) => _peers[deviceId];

  /// Returns up to [count] random alive peers, excluding [excludeId].
  /// Used by the Gossip engine to select relay targets.
  List<PeerInfo> randomSubset({required int count, String? excludeId}) {
    final candidates = alivePeers
        .where((p) => p.deviceId != excludeId)
        .toList()
      ..shuffle();
    return candidates.take(count).toList();
  }

  // ─── Listeners ────────────────────────────────────────────────────────────

  void addListener(PeerChangeCallback cb) => _listeners.add(cb);
  void removeListener(PeerChangeCallback cb) => _listeners.remove(cb);

  void _notify(PeerInfo peer, bool isOnline) {
    for (final cb in _listeners) {
      cb(peer, isOnline);
    }
  }
}

/// websocket_service.dart
/// ────────────────────────
/// Maintains the WebSocket connection to the central StageSync server.
///
/// ## Design Rules
///   * ONLY the elected leader ever calls [connect]. Follower devices route
///     their updates via the BLE mesh → leader → WebSocket.
///   * All outbound payloads are the same AES-GCM encrypted binary blobs used
///     on the BLE layer, ensuring end-to-end consistency. The server decrypts
///     using the same shared key stored server-side.
///   * Automatic reconnection uses exponential back-off (max 30 s).
///   * On disconnect, the leader immediately starts buffering outbound messages
///     in [_outboundBuffer]. These are flushed once reconnected.
library websocket_service;

import 'dart:async';
import 'dart:math' show min;
import 'dart:typed_data';

import 'package:web_socket_channel/web_socket_channel.dart';

/// Maximum number of bytes to buffer while disconnected.
const int kWsBufferMaxBytes = 512 * 1024; // 512 KB

/// Initial reconnect delay (ms).
const int kWsInitialReconnectMs = 500;

/// Maximum reconnect delay (ms).
const int kWsMaxReconnectMs = 30000;

// ─────────────────────────────────────────────────────────────────────────────

/// Callback for messages received from the server.
typedef ServerMessageCallback = void Function(Uint8List message);

/// Callback for connection state changes.
typedef ServerConnectionCallback = void Function(bool isConnected);

// ─────────────────────────────────────────────────────────────────────────────

class WebSocketService {
  String? _serverUrl;
  WebSocketChannel? _channel;
  StreamSubscription? _channelSub;

  bool _isConnected = false;
  bool _shouldReconnect = false;
  int _reconnectDelayMs = kWsInitialReconnectMs;
  Timer? _reconnectTimer;

  /// Buffered outbound messages accumulated while disconnected.
  final List<Uint8List> _outboundBuffer = [];
  int _outboundBufferBytes = 0;

  final ServerMessageCallback _onServerMessage;
  final ServerConnectionCallback _onConnectionChanged;

  WebSocketService({
    required ServerMessageCallback onServerMessage,
    required ServerConnectionCallback onConnectionChanged,
  })  : _onServerMessage = onServerMessage,
        _onConnectionChanged = onConnectionChanged;

  // ─── Public API ───────────────────────────────────────────────────────────

  bool get isConnected => _isConnected;

  /// Connects to [serverUrl] with automatic reconnection.
  /// Safe to call repeatedly – subsequent calls update the URL and reconnect.
  Future<void> connect(String serverUrl) async {
    _serverUrl = serverUrl;
    _shouldReconnect = true;
    await _openConnection();
  }

  /// Permanently disconnects and stops reconnection attempts.
  Future<void> disconnect() async {
    _shouldReconnect = false;
    _reconnectTimer?.cancel();
    await _closeChannel();
  }

  /// Sends an encrypted binary payload to the server.
  ///
  /// If currently disconnected, the message is buffered (up to
  /// [kWsBufferMaxBytes]). Older messages are dropped to make room when the
  /// buffer is full.
  void send(Uint8List encryptedPayload) {
    if (_isConnected && _channel != null) {
      _flushBuffer(); // flush any buffered messages first
      _channel!.sink.add(encryptedPayload);
    } else {
      _bufferMessage(encryptedPayload);
    }
  }

  // ─── Private – Connection ─────────────────────────────────────────────────

  Future<void> _openConnection() async {
    if (_serverUrl == null) return;
    await _closeChannel();

    try {
      _channel = WebSocketChannel.connect(Uri.parse(_serverUrl!));

      // Wait for the handshake to complete.
      await _channel!.ready;

      _channelSub = _channel!.stream.listen(
        _onRawMessage,
        onError: (_) => _onChannelClosed(),
        onDone: _onChannelClosed,
        cancelOnError: true,
      );

      _isConnected = true;
      _reconnectDelayMs = kWsInitialReconnectMs;
      _onConnectionChanged(true);
      _flushBuffer();
    } catch (_) {
      // Connection attempt failed – schedule retry.
      _scheduleReconnect();
    }
  }

  Future<void> _closeChannel() async {
    await _channelSub?.cancel();
    _channelSub = null;
    try {
      await _channel?.sink.close();
    } catch (_) {}
    _channel = null;
    if (_isConnected) {
      _isConnected = false;
      _onConnectionChanged(false);
    }
  }

  void _onChannelClosed() {
    _isConnected = false;
    _onConnectionChanged(false);
    _scheduleReconnect();
  }

  void _scheduleReconnect() {
    if (!_shouldReconnect) return;
    _reconnectTimer?.cancel();
    _reconnectTimer = Timer(
      Duration(milliseconds: _reconnectDelayMs),
      () => _openConnection(),
    );
    // Exponential back-off with jitter.
    _reconnectDelayMs = min(_reconnectDelayMs * 2, kWsMaxReconnectMs);
  }

  // ─── Private – Message Handling ──────────────────────────────────────────

  void _onRawMessage(dynamic data) {
    if (data is List<int>) {
      _onServerMessage(Uint8List.fromList(data));
    } else if (data is Uint8List) {
      _onServerMessage(data);
    }
    // Text frames are ignored (protocol is binary-only).
  }

  // ─── Private – Outbound Buffer ────────────────────────────────────────────

  void _bufferMessage(Uint8List payload) {
    // If adding this message would exceed the byte cap, evict the oldest entries.
    while (_outboundBufferBytes + payload.length > kWsBufferMaxBytes &&
        _outboundBuffer.isNotEmpty) {
      final evicted = _outboundBuffer.removeAt(0);
      _outboundBufferBytes -= evicted.length;
    }
    _outboundBuffer.add(payload);
    _outboundBufferBytes += payload.length;
  }

  void _flushBuffer() {
    if (_outboundBuffer.isEmpty || !_isConnected || _channel == null) return;
    final toSend = List<Uint8List>.from(_outboundBuffer);
    _outboundBuffer.clear();
    _outboundBufferBytes = 0;
    for (final msg in toSend) {
      _channel!.sink.add(msg);
    }
  }
}

/// chat_provider.dart
/// ────────────────────
/// Riverpod state management for the Chat feature.
/// Listens to [chatEventStreamProvider] and maintains a deduped message list.
library chat_provider;

import 'package:flutter_riverpod/flutter_riverpod.dart';

import '../../network/isolate/isolate_messages.dart';
import 'network_state_provider.dart';

// ─────────────────────────────────────────────────────────────────────────────
// Display model (UI-only, not persisted)
// ─────────────────────────────────────────────────────────────────────────────

class ChatMessageDisplay {
  final String messageId;
  final String senderLabel;
  final String content;
  final DateTime timestamp;
  final bool isMine;

  const ChatMessageDisplay({
    required this.messageId,
    required this.senderLabel,
    required this.content,
    required this.timestamp,
    required this.isMine,
  });

  factory ChatMessageDisplay.fromEvent(ChatMessageReceivedEvent e) =>
      ChatMessageDisplay(
        messageId: e.messageId,
        senderLabel: e.senderShortLabel,
        content: e.content,
        timestamp: DateTime.fromMillisecondsSinceEpoch(e.timestampMs),
        isMine: e.isMine,
      );
}

// ─────────────────────────────────────────────────────────────────────────────
// StateNotifier
// ─────────────────────────────────────────────────────────────────────────────

class ChatNotifier extends StateNotifier<List<ChatMessageDisplay>> {
  final Ref _ref;
  ProviderSubscription? _sub;

  ChatNotifier(this._ref) : super([]) {
    _sub = _ref.listen<AsyncValue<ChatMessageReceivedEvent>>(
      chatEventStreamProvider,
      (_, next) {
        next.whenData(_onEvent);
      },
    );
  }

  void _onEvent(ChatMessageReceivedEvent event) {
    // Deduplicate by messageId.
    if (state.any((m) => m.messageId == event.messageId)) return;
    state = [...state, ChatMessageDisplay.fromEvent(event)];
    // Keep at most 200 messages in memory.
    if (state.length > 200) {
      state = state.sublist(state.length - 200);
    }
  }

  /// Send a new chat message via the network isolate.
  Future<void> sendMessage(String content) async {
    if (content.trim().isEmpty) return;
    final manager = await _ref.read(networkIsolateManagerProvider.future);
    manager.send(SendChatMessageCommand(content: content.trim()));
  }

  @override
  void dispose() {
    _sub?.close();
    super.dispose();
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Providers
// ─────────────────────────────────────────────────────────────────────────────

final chatProvider =
    StateNotifierProvider<ChatNotifier, List<ChatMessageDisplay>>((ref) {
  return ChatNotifier(ref);
});

/// network_state_provider.dart
/// ─────────────────────────────
/// Riverpod providers that expose the [NetworkIsolateManager] and its event
/// stream to the entire widget tree.
///
/// ## How to use from a widget
///
/// ```dart
/// // Read the live network status:
/// final status = ref.watch(networkStatusProvider);
///
/// // Watch all item updates:
/// ref.listen(itemUpdatedProvider, (prev, next) { … });
///
/// // Send a command (e.g. from a scan button):
/// ref.read(networkIsolateManagerProvider).send(
///   ScanItemCommand(itemId: id, statusId: 1, timestampMs: now),
/// );
/// ```
library network_state_provider;

import 'package:flutter_riverpod/flutter_riverpod.dart';

import '../../network/isolate/isolate_messages.dart';
import '../../network/isolate/network_isolate_manager.dart';
import '../../network/platform/platform_capabilities.dart';

// ─────────────────────────────────────────────────────────────────────────────
// 1.  Device ID provider
//     In production, persist this in SharedPreferences on first launch.
// ─────────────────────────────────────────────────────────────────────────────

final deviceIdProvider = Provider<String>((ref) {
  // TODO(production): load from SharedPreferences; generate with Uuid() once.
  // For now a compile-time placeholder is used so the app compiles and runs.
  const fallbackId = 'device-0000-default';
  return fallbackId;
});

// ─────────────────────────────────────────────────────────────────────────────
// 2.  NetworkIsolateManager  (async – initialises background isolate)
// ─────────────────────────────────────────────────────────────────────────────

final networkIsolateManagerProvider =
    FutureProvider<NetworkIsolateManager>((ref) async {
  final deviceId = ref.read(deviceIdProvider);
  final manager = NetworkIsolateManager();
  await manager.init(deviceId: deviceId);

  // Dispose gracefully when the ProviderScope is destroyed.
  ref.onDispose(manager.dispose);

  return manager;
});

// ─────────────────────────────────────────────────────────────────────────────
// 3.  Raw event stream from the network isolate
// ─────────────────────────────────────────────────────────────────────────────

final networkEventStreamProvider = StreamProvider<NetworkEvent>((ref) async* {
  // Wait for the manager to be initialised.
  final managerAsync = await ref.watch(
    networkIsolateManagerProvider.future,
  );
  yield* managerAsync.events;
});

// ─────────────────────────────────────────────────────────────────────────────
// 4.  Derived providers for specific event types
// ─────────────────────────────────────────────────────────────────────────────

/// Latest [NetworkStatusEvent] – updated roughly every 5 seconds.
/// The UI can use this to show peer count, sync status, and leader badge.
final networkStatusProvider = Provider<NetworkStatusEvent?>((ref) {
  final stream = ref.watch(networkEventStreamProvider);
  return stream.whenData((event) {
    if (event is NetworkStatusEvent) return event;
    return null;
  }).value;
});

/// Latest [LeaderChangedEvent].
final leaderChangedProvider = Provider<LeaderChangedEvent?>((ref) {
  final stream = ref.watch(networkEventStreamProvider);
  return stream.whenData((event) {
    if (event is LeaderChangedEvent) return event;
    return null;
  }).value;
});

/// Stream of [ItemUpdatedEvent]s for live inventory updates.
final itemUpdateStreamProvider = StreamProvider<ItemUpdatedEvent>((ref) async* {
  await for (final event in ref.watch(networkEventStreamProvider.stream)) {
    if (event is ItemUpdatedEvent) yield event;
  }
});

/// Stream of [ChatMessageReceivedEvent]s for the chat screen.
final chatEventStreamProvider = StreamProvider<ChatMessageReceivedEvent>((ref) async* {
  await for (final event in ref.watch(networkEventStreamProvider.stream)) {
    if (event is ChatMessageReceivedEvent) yield event;
  }
});

/// Derived live peer list from the latest [NetworkStatusEvent].
final peerListProvider = Provider<List<PeerStatusInfo>>((ref) {
  return ref.watch(networkStatusProvider)?.peers ?? const [];
});

/// Erkennt die Plattform-Fähigkeiten einmalig beim App-Start.
final platformCapabilitiesProvider = Provider<PlatformCapabilities>((ref) {
  return PlatformCapabilities.detect();
});

/// Convenience: Is BLE available on the current platform?
final hasBleProvider = Provider<bool>((ref) {
  return ref.watch(platformCapabilitiesProvider).hasBle;
});

/// Latest score breakdown from the latest [NetworkStatusEvent].
final scoreBreakdownProvider = Provider<NetworkScoreBreakdown>((ref) {
  return ref.watch(networkStatusProvider)?.scoreBreakdown ??
      NetworkScoreBreakdown.zero;
});

/// Convenience derived state: has the network isolate been initialised?
final isNetworkReadyProvider = Provider<bool>((ref) {
  return ref.watch(networkIsolateManagerProvider).hasValue;
});

/// chat_screen.dart
/// ──────────────────
/// BLE-Mesh Chat Demo Screen.
/// Nachrichten werden über das Gossip-Protokoll im Mesh verteilt und
/// AES-256-GCM verschlüsselt übertragen.
library chat_screen;

import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';

import '../providers/chat_provider.dart';
import '../providers/network_state_provider.dart';

class ChatScreen extends ConsumerStatefulWidget {
  const ChatScreen({super.key});

  @override
  ConsumerState<ChatScreen> createState() => _ChatScreenState();
}

class _ChatScreenState extends ConsumerState<ChatScreen> {
  final TextEditingController _controller = TextEditingController();
  final ScrollController _scrollController = ScrollController();

  @override
  void dispose() {
    _controller.dispose();
    _scrollController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final messages = ref.watch(chatProvider);
    final status = ref.watch(networkStatusProvider);
    final isReady = ref.watch(isNetworkReadyProvider);
    final colors = Theme.of(context).colorScheme;

    // Auto-scroll to bottom when new messages arrive.
    ref.listen(chatProvider, (prev, next) {
      if (next.length > (prev?.length ?? 0)) {
        _scrollToBottom();
      }
    });

    return Scaffold(
      appBar: AppBar(
        title: const Text('Mesh Chat'),
        bottom: PreferredSize(
          preferredSize: const Size.fromHeight(28),
          child: _ChatSubtitle(
            peerCount: status?.connectedPeerCount ?? 0,
            syncStatus: status?.syncStatus,
          ),
        ),
      ),
      body: Column(
        children: [
          // ── Message List ──────────────────────────────────────────────
          Expanded(
            child: messages.isEmpty
                ? const _EmptyChatState()
                : ListView.builder(
                    controller: _scrollController,
                    padding: const EdgeInsets.symmetric(
                        horizontal: 12, vertical: 8),
                    itemCount: messages.length,
                    itemBuilder: (context, i) => _ChatBubble(
                      message: messages[i],
                    ),
                  ),
          ),

          // ── Divider + Info-Chip ───────────────────────────────────────
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 4),
            child: Row(
              children: [
                const Icon(Icons.security, size: 12, color: Colors.grey),
                const SizedBox(width: 4),
                Text(
                  'AES-256-GCM via BLE Mesh',
                  style: Theme.of(context)
                      .textTheme
                      .labelSmall
                      ?.copyWith(color: Colors.grey),
                ),
                const Spacer(),
                if (status?.pendingQueuedPackets != null &&
                    status!.pendingQueuedPackets > 0)
                  Text(
                    '${status.pendingQueuedPackets} in Queue',
                    style: const TextStyle(
                        fontSize: 10, color: Colors.orange),
                  ),
              ],
            ),
          ),

          // ── Input Row ─────────────────────────────────────────────────
          Container(
            decoration: BoxDecoration(
              color: colors.surface,
              border: Border(
                top: BorderSide(color: colors.outlineVariant),
              ),
            ),
            padding: EdgeInsets.only(
              left: 12,
              right: 8,
              top: 8,
              bottom: MediaQuery.of(context).viewInsets.bottom + 8,
            ),
            child: Row(
              children: [
                Expanded(
                  child: TextField(
                    controller: _controller,
                    enabled: isReady,
                    maxLength: 180,
                    maxLines: null,
                    keyboardType: TextInputType.multiline,
                    textCapitalization: TextCapitalization.sentences,
                    decoration: InputDecoration(
                      hintText: isReady
                          ? 'Nachricht ins Mesh senden…'
                          : 'Netzwerk wird initialisiert…',
                      border: OutlineInputBorder(
                        borderRadius: BorderRadius.circular(24),
                        borderSide: BorderSide.none,
                      ),
                      filled: true,
                      fillColor: colors.surfaceContainerHighest,
                      contentPadding: const EdgeInsets.symmetric(
                          horizontal: 16, vertical: 10),
                      counterText: '', // hide character counter
                    ),
                    onSubmitted: (_) => _send(),
                  ),
                ),
                const SizedBox(width: 8),
                FilledButton(
                  onPressed: isReady ? _send : null,
                  style: FilledButton.styleFrom(
                    shape: const CircleBorder(),
                    padding: const EdgeInsets.all(14),
                  ),
                  child: const Icon(Icons.send),
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }

  void _send() {
    final text = _controller.text.trim();
    if (text.isEmpty) return;
    ref.read(chatProvider.notifier).sendMessage(text);
    _controller.clear();
    _scrollToBottom();
  }

  void _scrollToBottom() {
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (_scrollController.hasClients) {
        _scrollController.animateTo(
          _scrollController.position.maxScrollExtent,
          duration: const Duration(milliseconds: 300),
          curve: Curves.easeOut,
        );
      }
    });
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Chat Subtitle (AppBar.bottom)
// ─────────────────────────────────────────────────────────────────────────────

class _ChatSubtitle extends StatelessWidget {
  final int peerCount;
  final NetworkSyncStatus? syncStatus;

  const _ChatSubtitle({required this.peerCount, required this.syncStatus});

  @override
  Widget build(BuildContext context) {
    final (label, color) = switch (syncStatus) {
      NetworkSyncStatus.syncing ||
      NetworkSyncStatus.upToDate =>
        ('Server + $peerCount Peers', Colors.green),
      NetworkSyncStatus.meshOnly =>
        ('$peerCount Peers via BLE Mesh', Colors.blueAccent),
      _ => ('Offline – Store & Forward aktiv', Colors.orange),
    };

    return Container(
      padding: const EdgeInsets.only(left: 16, right: 16, bottom: 6),
      alignment: Alignment.centerLeft,
      child: Row(
        children: [
          Container(
            width: 6,
            height: 6,
            decoration: BoxDecoration(color: color, shape: BoxShape.circle),
          ),
          const SizedBox(width: 6),
          Text(label,
              style: TextStyle(fontSize: 11, color: color)),
        ],
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Chat Bubble
// ─────────────────────────────────────────────────────────────────────────────

class _ChatBubble extends StatelessWidget {
  final ChatMessageDisplay message;
  const _ChatBubble({required this.message});

  @override
  Widget build(BuildContext context) {
    final colors = Theme.of(context).colorScheme;
    final isMine = message.isMine;

    final timeLabel =
        '${message.timestamp.hour.toString().padLeft(2, '0')}'
        ':${message.timestamp.minute.toString().padLeft(2, '0')}';

    return Padding(
      padding: const EdgeInsets.symmetric(vertical: 3),
      child: Column(
        crossAxisAlignment:
            isMine ? CrossAxisAlignment.end : CrossAxisAlignment.start,
        children: [
          if (!isMine)
            Padding(
              padding: const EdgeInsets.only(left: 12, bottom: 2),
              child: Text(
                message.senderLabel,
                style: Theme.of(context).textTheme.labelSmall?.copyWith(
                      color: _colorForLabel(message.senderLabel),
                    ),
              ),
            ),
          Row(
            mainAxisAlignment:
                isMine ? MainAxisAlignment.end : MainAxisAlignment.start,
            crossAxisAlignment: CrossAxisAlignment.end,
            children: [
              if (!isMine) ...[
                CircleAvatar(
                  radius: 14,
                  backgroundColor:
                      _colorForLabel(message.senderLabel).withOpacity(0.2),
                  child: Text(
                    message.senderLabel.substring(
                        message.senderLabel.length > 1
                            ? message.senderLabel.length - 1
                            : 0),
                    style: TextStyle(
                        fontSize: 10,
                        color: _colorForLabel(message.senderLabel)),
                  ),
                ),
                const SizedBox(width: 6),
              ],
              Flexible(
                child: Container(
                  padding: const EdgeInsets.symmetric(
                      horizontal: 14, vertical: 10),
                  decoration: BoxDecoration(
                    color: isMine
                        ? colors.primaryContainer
                        : colors.surfaceContainerHigh,
                    borderRadius: BorderRadius.only(
                      topLeft: const Radius.circular(18),
                      topRight: const Radius.circular(18),
                      bottomLeft:
                          Radius.circular(isMine ? 18 : 4),
                      bottomRight:
                          Radius.circular(isMine ? 4 : 18),
                    ),
                  ),
                  child: Text(
                    message.content,
                    style: TextStyle(
                      color: isMine
                          ? colors.onPrimaryContainer
                          : colors.onSurface,
                    ),
                  ),
                ),
              ),
              if (isMine) const SizedBox(width: 6),
            ],
          ),
          Padding(
            padding: EdgeInsets.only(
                left: isMine ? 0 : 40,
                right: isMine ? 0 : 0,
                top: 2),
            child: Text(
              timeLabel,
              style: const TextStyle(fontSize: 10, color: Colors.grey),
            ),
          ),
        ],
      ),
    );
  }

  static const List<Color> _colors = [
    Colors.blueAccent,
    Colors.purpleAccent,
    Colors.teal,
    Colors.deepOrangeAccent,
    Colors.indigo,
    Colors.pinkAccent,
  ];

  Color _colorForLabel(String label) =>
      _colors[label.codeUnits.fold(0, (a, b) => a + b) % _colors.length];
}

// ─────────────────────────────────────────────────────────────────────────────
// Empty State
// ─────────────────────────────────────────────────────────────────────────────

class _EmptyChatState extends StatelessWidget {
  const _EmptyChatState();

  @override
  Widget build(BuildContext context) {
    return Center(
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          Icon(
            Icons.chat_bubble_outline,
            size: 60,
            color: Colors.grey.withOpacity(0.4),
          ),
          const SizedBox(height: 16),
          const Text(
            'Noch keine Nachrichten',
            style: TextStyle(color: Colors.grey, fontSize: 16),
          ),
          const SizedBox(height: 8),
          const Text(
            'Schreibe die erste Nachricht –\nsie wird verschlüsselt ins BLE-Mesh gesendet.',
            textAlign: TextAlign.center,
            style: TextStyle(color: Colors.grey, fontSize: 12),
          ),
        ],
      ),
    );
  }
}

/// home_screen.dart
/// ──────────────────
/// Dashboard-Startseite der StageSync App.
/// Zeigt eine Übersicht der wichtigsten Netzwerk-Metriken und Quick-Actions.
library home_screen;

import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';

import '../../network/isolate/isolate_messages.dart';
import '../providers/network_state_provider.dart';

class HomeScreen extends ConsumerWidget {
  const HomeScreen({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final status = ref.watch(networkStatusProvider);
    final isLeader = ref.watch(isLeaderProvider);
    final breakdown = ref.watch(scoreBreakdownProvider);
    final colors = Theme.of(context).colorScheme;

    return Scaffold(
      body: CustomScrollView(
        slivers: [
          // ── Hero-Header ──────────────────────────────────────────────────
          SliverAppBar(
            expandedHeight: 160,
            pinned: true,
            flexibleSpace: FlexibleSpaceBar(
              title: const Text('StageSync'),
              background: Container(
                decoration: BoxDecoration(
                  gradient: LinearGradient(
                    begin: Alignment.topLeft,
                    end: Alignment.bottomRight,
                    colors: [
                      colors.primaryContainer,
                      colors.primary.withOpacity(0.7),
                    ],
                  ),
                ),
                child: Center(
                  child: Icon(
                    Icons.theater_comedy,
                    size: 64,
                    color: colors.onPrimaryContainer.withOpacity(0.3),
                  ),
                ),
              ),
            ),
          ),

          SliverPadding(
            padding: const EdgeInsets.all(16),
            sliver: SliverList(
              delegate: SliverChildListDelegate([
                // ── Status-Karten-Reihe ────────────────────────────────────
                Row(
                  children: [
                    Expanded(
                      child: _StatCard(
                        icon: isLeader ? Icons.star : Icons.hub,
                        label: isLeader ? 'Leader' : 'Follower',
                        value: isLeader ? '★' : '○',
                        color: isLeader ? Colors.amber : colors.secondary,
                      ),
                    ),
                    const SizedBox(width: 8),
                    Expanded(
                      child: _StatCard(
                        icon: Icons.bluetooth_connected,
                        label: 'Peers',
                        value: '${status?.connectedPeerCount ?? 0}',
                        color: colors.tertiary,
                      ),
                    ),
                    const SizedBox(width: 8),
                    Expanded(
                      child: _StatCard(
                        icon: _syncIcon(status?.syncStatus),
                        label: _syncLabel(status?.syncStatus),
                        value: _syncShort(status?.syncStatus),
                        color: _syncColor(status?.syncStatus, context),
                      ),
                    ),
                  ],
                ),

                const SizedBox(height: 16),

                // ── Election Score ────────────────────────────────────────
                _ScoreCard(breakdown: breakdown),

                const SizedBox(height: 16),

                // ── Warteschlange ─────────────────────────────────────────
                if ((status?.pendingQueuedPackets ?? 0) > 0)
                  _QueueWarningCard(count: status!.pendingQueuedPackets),

                const SizedBox(height: 16),

                // ── Quick-Actions ─────────────────────────────────────────
                Text('Aktionen',
                    style: Theme.of(context).textTheme.titleMedium),
                const SizedBox(height: 8),
                _QuickActionButton(
                  icon: Icons.how_to_vote,
                  label: 'Neue Leader-Wahl starten',
                  onTap: () {
                    ref
                        .read(networkIsolateManagerProvider)
                        .whenData((m) => m.send(ForceElectionCommand()));
                  },
                ),
                const SizedBox(height: 8),
                _QuickActionButton(
                  icon: Icons.refresh,
                  label: 'Status aktualisieren',
                  onTap: () {
                    ref
                        .read(networkIsolateManagerProvider)
                        .whenData((m) => m.send(QueryStatusCommand()));
                  },
                ),
                const SizedBox(height: 8),
                _QuickActionButton(
                  icon: Icons.cloud_upload,
                  label: 'Mit Demo-Server verbinden',
                  onTap: () {
                    ref.read(networkIsolateManagerProvider).whenData(
                          (m) => m.send(ConnectToServerCommand(
                              'wss://stagesync-demo.example.com/ws')),
                        );
                  },
                ),

                const SizedBox(height: 24),
              ]),
            ),
          ),
        ],
      ),
    );
  }

  IconData _syncIcon(NetworkSyncStatus? s) => switch (s) {
        NetworkSyncStatus.syncing => Icons.cloud_sync,
        NetworkSyncStatus.upToDate => Icons.cloud_done,
        NetworkSyncStatus.meshOnly => Icons.bluetooth_connected,
        _ => Icons.cloud_off,
      };

  String _syncLabel(NetworkSyncStatus? s) => switch (s) {
        NetworkSyncStatus.syncing => 'Sync',
        NetworkSyncStatus.upToDate => 'Aktuell',
        NetworkSyncStatus.meshOnly => 'Mesh',
        _ => 'Offline',
      };

  String _syncShort(NetworkSyncStatus? s) => switch (s) {
        NetworkSyncStatus.syncing => '↑↓',
        NetworkSyncStatus.upToDate => '✓',
        NetworkSyncStatus.meshOnly => 'BLE',
        _ => '✕',
      };

  Color _syncColor(NetworkSyncStatus? s, BuildContext ctx) {
    final c = Theme.of(ctx).colorScheme;
    return switch (s) {
      NetworkSyncStatus.syncing => Colors.greenAccent,
      NetworkSyncStatus.upToDate => Colors.green,
      NetworkSyncStatus.meshOnly => c.tertiary,
      _ => Colors.redAccent,
    };
  }
}

