class _ScoreBreakdownBar extends StatelessWidget {
  final NetworkScoreBreakdown breakdown;
  const _ScoreBreakdownBar({required this.breakdown});

  @override
  Widget build(BuildContext context) {
    final maxScore = 100 + 50 + 100; // max possible = 250
    final fraction = (breakdown.total / maxScore).clamp(0.0, 1.0);
    final color = fraction > 0.6
        ? Colors.green
        : fraction > 0.3
            ? Colors.orange
            : Colors.red;

    return ClipRRect(
      borderRadius: BorderRadius.circular(4),
      child: LinearProgressIndicator(
        value: fraction,
        minHeight: 8,
        backgroundColor: Colors.white12,
        valueColor: AlwaysStoppedAnimation(color),
      ),
    );
  }
}

class _ScoreChip extends StatelessWidget {
  final String label;
  final String value;
  final bool active;
  final Color color;

  const _ScoreChip({
    required this.label,
    required this.value,
    required this.active,
    required this.color,
  });

  @override
  Widget build(BuildContext context) {
    return Column(
      children: [
        Container(
          padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
          decoration: BoxDecoration(
            color: active ? color.withOpacity(0.2) : Colors.white10,
            borderRadius: BorderRadius.circular(8),
            border: Border.all(
              color: active ? color : Colors.transparent,
              width: 1,
            ),
          ),
          child: Text(
            value,
            style: TextStyle(
              fontSize: 13,
              fontWeight: FontWeight.bold,
              color: active ? color : Colors.grey,
            ),
          ),
        ),
        const SizedBox(height: 2),
        Text(label,
            style: Theme.of(context).textTheme.labelSmall?.copyWith(
                  color: active ? null : Colors.grey,
                )),
      ],
    );
  }
}

